  7→export const loadSession = async (): Promise<SessionData | null> => {
  8→  try {
  9→    const file = Bun.file(SESSION_PATH);
 10→    const data = await file.json();
 11→    if (data && data.did && data.accessJwt) {
 12→      return data as SessionData;
 13→    }
 14→    return null;
 15→  } catch {
 16→    return null;
 17→  }
