 28→export class BlueskyClient {
 29→  private agent: BskyAgent;
 30→  private _did: string | null = null;
 31→
 32→  constructor(service: string = DEFAULT_SERVICE) {
 33→    this.agent = new BskyAgent({
 34→      service,
 35→      persistSession: (_evt, sessionData) => {
 36→        if (sessionData) {
 37→          saveSession({
 38→            handle: sessionData.handle,
 39→            did: sessionData.did,
 40→            accessJwt: sessionData.accessJwt,
 41→            refreshJwt: sessionData.refreshJwt,
 42→            service,
 43→          });
 44→        }
 45→      },
 46→    });
 47→  }
 48→
 49→  get did(): string | null {
 50→    return this._did;
 51→  }
 52→
 53→  get isAuthenticated(): boolean {
 54→    return this._did !== null;
 55→  }
 56→
 57→  login = async (identifier: string, password: string): Promise<{ success: boolean; error?: string }> => {
 58→    try {
 59→      const response = await this.agent.login({ identifier, password });
 60→      this._did = response.data.did;
 61→      await saveSession({
 62→        handle: response.data.handle,
 63→        did: response.data.did,
 64→        accessJwt: response.data.accessJwt,
 65→        refreshJwt: response.data.refreshJwt,
 66→        service: DEFAULT_SERVICE,
 67→      });
 68→      return { success: true };
 69→    } catch (err) {
 70→      const message = err instanceof Error ? err.message : "Unknown login error";
 71→      return { success: false, error: message };
 72→    }
 73→  };
 74→
 75→  resumeSession = async (): Promise<boolean> => {
 76→    const session = await loadSession();
 77→    if (!session) return false;
 78→    try {
 79→      await this.agent.resumeSession({
 80→        did: session.did,
 81→        handle: session.handle,
 82→        accessJwt: session.accessJwt,
 83→        refreshJwt: session.refreshJwt,
 84→        active: true,
 85→      });
 86→      this._did = session.did;
 87→      return true;
 88→    } catch {
 89→      await clearSession();
 90→      return false;
 91→    }
 92→  };
 93→
 94→  logout = async (): Promise<void> => {
 95→    this._did = null;
 96→    await clearSession();
 97→  };
