100→    const response = await this.agent.getTimeline({ cursor, limit });
101→    const feed: FeedItem[] = response.data.feed.map((item) => ({
102→      post: mapPostView(item.post),
103→      reason: item.reason as FeedItem["reason"],
104→      reply: item.reply
105→        ? {
106→            root: mapPostView(item.reply.root),
107→            parent: mapPostView(item.reply.parent),
108→          }
109→        : undefined,
110→    }));
111→    return { feed, cursor: response.data.cursor };
112→  };
