142→      banner: response.data.banner,
143→      followersCount: response.data.followersCount ?? 0,
144→      followsCount: response.data.followsCount ?? 0,
145→      postsCount: response.data.postsCount ?? 0,
146→      viewer: response.data.viewer as ProfileView["viewer"],
147→    };
148→  };
149→
150→  getAuthorFeed = async (
