154→  ): Promise<{ feed: PostView[]; cursor?: string }> => {
155→    const response = await this.agent.getAuthorFeed({ actor, cursor, limit });
156→    const feed = response.data.feed.map((item) => mapPostView(item.post));
157→    return { feed, cursor: response.data.cursor };
158→  };
159→
160→  follow = async (did: string): Promise<string> => {
161→    const response = await this.agent.follow(did);
