170→    const response = await this.agent.searchActors({ term, limit });
171→    return response.data.actors.map((actor) => ({
172→      did: actor.did,
173→      handle: actor.handle,
174→      displayName: actor.displayName,
175→      description: actor.description,
176→      avatar: actor.avatar,
177→      banner: undefined,
178→      followersCount: actor.viewer ? 0 : 0,
179→      followsCount: 0,
180→      postsCount: 0,
181→      viewer: actor.viewer as ProfileView["viewer"],
182→    }));
183→  };
184→}
