186→const mapPostView = (post: Record<string, unknown>): PostView => {
187→  const author = post.author as Record<string, unknown>;
188→  const record = post.record as Record<string, unknown>;
189→  const viewer = post.viewer as Record<string, unknown> | undefined;
190→  return {
191→    uri: post.uri as string,
192→    cid: post.cid as string,
193→    author: {
194→      did: author.did as string,
195→      handle: author.handle as string,
196→      displayName: author.displayName as string | undefined,
197→      avatar: author.avatar as string | undefined,
198→    },
199→    record: {
200→      text: record.text as string,
201→      createdAt: record.createdAt as string,
202→      langs: record.langs as string[] | undefined,
203→      facets: record.facets as PostView["record"]["facets"],
204→    },
205→    replyCount: (post.replyCount as number) ?? 0,
206→    repostCount: (post.repostCount as number) ?? 0,
207→    likeCount: (post.likeCount as number) ?? 0,
208→    indexedAt: post.indexedAt as string,
209→    viewer: viewer
210→      ? {
211→          like: viewer.like as string | undefined,
212→          repost: viewer.repost as string | undefined,
213→          muted: viewer.muted as boolean | undefined,
214→          blockedBy: viewer.blockedBy as boolean | undefined,
215→        }
216→      : undefined,
217→  };
218→};
