  1→import type { SortMode } from './types'
  2→import {
  3→  getThreads,
  4→  getThread,
  5→  createThread,
  6→  createReply,
  7→  voteOnThread,
  8→  voteOnReply,
  9→} from './store'
 10→import {
 11→  renderThreadList,
 12→  renderThreadDetail,
 13→  renderNewThreadForm,
 14→} from './render'
 15→
 16→type RouteResult = {
 17→  html?: string
 18→  json?: unknown
 19→  status?: number
 20→  error?: string
 21→}
 22→
 23→export const handleRequest = async (
 24→  method: string,
 25→  path: string,
 26→  params: Record<string, string>,
 27→  body?: Record<string, unknown>
 28→): Promise<RouteResult> => {
 29→
 30→  // GET / — thread list
 31→  if (method === 'GET' && (path === '/' || path === '/threads')) {
 32→    const sort = (params.sort as SortMode) || 'newest'
 33→    const search = params.search || ''
 34→    const threads = await getThreads(sort, search)
 35→    return { html: renderThreadList(threads, sort, search) }
 36→  }
 37→
 38→  // GET /threads/new — new thread form
 39→  if (method === 'GET' && path === '/threads/new') {
 40→    return { html: renderNewThreadForm() }
 41→  }
 42→
 43→  // GET /threads/:id — thread detail
 44→  if (method === 'GET' && path.startsWith('/threads/')) {
 45→    const id = path.replace('/threads/', '')
 46→    const thread = await getThread(id)
 47→    if (!thread) return { status: 404, error: 'Thread not found' }
 48→    return { html: renderThreadDetail(thread) }
 49→  }
 50→
 51→  // POST /threads — create thread
 52→  if (method === 'POST' && path === '/threads') {
 53→    const { title, body: threadBody, author } = body as Record<string, string>
 54→    if (!title?.trim() || !threadBody?.trim() || !author?.trim()) {
 55→      return { status: 400, error: 'Title, body, and author are required' }
 56→    }
 57→    const thread = await createThread(title, threadBody, author)
 58→    return { json: thread, status: 201 }
 59→  }
 60→
 61→  // POST /threads/:id/replies — create reply
 62→  if (method === 'POST' && path.match(/^\/threads\/[^/]+\/replies$/)) {
 63→    const threadId = path.split('/')[2]
 64→    const { body: replyBody, author, parentReplyId } = body as Record<string, string>
 65→    if (!replyBody?.trim() || !author?.trim()) {
 66→      return { status: 400, error: 'Body and author are required' }
 67→    }
 68→    const reply = await createReply(threadId, replyBody, author, parentReplyId || null)
 69→    if (!reply) return { status: 404, error: 'Thread or parent reply not found' }
 70→    return { json: reply, status: 201 }
 71→  }
 72→
 73→  // POST /threads/:id/vote — vote on thread
 74→  if (method === 'POST' && path.match(/^\/threads\/[^/]+\/vote$/)) {
 75→    const threadId = path.split('/')[2]
 76→    const { userId, value } = body as { userId: string; value: number }
 77→    if (!userId || (value !== 1 && value !== -1)) {
 78→      return { status: 400, error: 'userId and value (1 or -1) are required' }
 79→    }
 80→    const thread = await voteOnThread(threadId, userId, value as 1 | -1)
 81→    if (!thread) return { status: 404, error: 'Thread not found' }
 82→    return { json: thread }
 83→  }
 84→
 85→  // POST /threads/:id/replies/:replyId/vote — vote on reply
 86→  if (method === 'POST' && path.match(/^\/threads\/[^/]+\/replies\/[^/]+\/vote$/)) {
 87→    const parts = path.split('/')
 88→    const threadId = parts[2]
 89→    const replyId = parts[4]
 90→    const { userId, value } = body as { userId: string; value: number }
 91→    if (!userId || (value !== 1 && value !== -1)) {
 92→      return { status: 400, error: 'userId and value (1 or -1) are required' }
 93→    }
 94→    const reply = await voteOnReply(threadId, replyId, userId, value as 1 | -1)
 95→    if (!reply) return { status: 404, error: 'Thread or reply not found' }
 96→    return { json: reply }
 97→  }
 98→
 99→  return { status: 404, error: 'Not found' }
100→}
