 3→const parseBody = async (req: Request): Promise<Record<string, unknown> | undefined> => {
 4→  const contentType = req.headers.get('content-type') || ''
 5→  if (contentType.includes('application/json')) {
 6→    return req.json()
 7→  }
 8→  if (contentType.includes('application/x-www-form-urlencoded')) {
 9→    const text = await req.text()
10→    const params = new URLSearchParams(text)
11→    const result: Record<string, string> = {}
12→    params.forEach((v, k) => { result[k] = v })
13→    return result
14→  }
15→  return undefined
16→}
17→
18→const server = Bun.serve({
19→  port: Number(process.env.PORT) || 3000,
20→  fetch: async (req) => {
21→    const url = new URL(req.url)
22→    const method = req.method
23→    const path = url.pathname
24→    const params: Record<string, string> = {}
25→    url.searchParams.forEach((v, k) => { params[k] = v })
26→
27→    const body = method === 'POST' ? await parseBody(req) : undefined
28→    const result = await handleRequest(method, path, params, body)
29→
30→    if (result.error) {
31→      return new Response(JSON.stringify({ error: result.error }), {
32→        status: result.status || 500,
33→        headers: { 'Content-Type': 'application/json' },
34→      })
35→    }
36→
37→    if (result.html) {
38→      const page = `<!DOCTYPE html>
39→<html lang="en">
40→<head>
41→  <meta charset="UTF-8">
42→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
43→  <title>Discussion Forum</title>
44→  <style>
45→    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
46→    body { background: #f8f9fa; }
47→    a { color: inherit; text-decoration: none; }
48→    button { cursor: pointer; }
49→    input, textarea { font-family: inherit; }
50→  </style>
51→</head>
52→<body>${result.html}</body>
53→</html>`
54→      return new Response(page, {
55→        status: result.status || 200,
56→        headers: { 'Content-Type': 'text/html; charset=utf-8' },
57→      })
58→    }
59→
60→    if (result.json) {
