import type { DataRow, DetectedFields, FieldInfo, ParsedChartData } from './types'

export const detectFields = (data: DataRow[]): DetectedFields => {
  if (data.length === 0) return { numeric: [], categorical: [] }

  const firstRow = data[0]
  const numeric: FieldInfo[] = []
  const categorical: FieldInfo[] = []

  for (const key of Object.keys(firstRow)) {
    const isNumeric = data.every((row) => {
      const val = row[key]
      if (val === null || val === undefined || val === '') return true
      return typeof val === 'number' || !isNaN(Number(val))
    })

    const hasAnyValue = data.some((row) => {
      const val = row[key]
      return val !== null && val !== undefined && val !== ''
    })

    if (!hasAnyValue) continue

    if (isNumeric) {
      numeric.push({ name: key, type: 'numeric' })
    } else {
      categorical.push({ name: key, type: 'categorical' })
    }
  }

  return { numeric, categorical }
}

export const parseChartData = (
  data: DataRow[],
  categoryField: string,
  valueFields: string[],
): ParsedChartData => {
  const categories = data.map((row) => String(row[categoryField] ?? ''))

  const series = valueFields.map((field) => ({
    name: field,
    values: data.map((row) => {
      const val = row[field]
      if (typeof val === 'number') return val
      const parsed = Number(val)
      return isNaN(parsed) ? 0 : parsed
    }),
  }))

  return { categories, series }
}

export const validateJsonData = (input: string): { data: DataRow[] | null; error: string | null } => {
  try {
    const parsed = JSON.parse(input)
    if (!Array.isArray(parsed)) {
      return { data: null, error: 'Data must be a JSON array' }
    }
    if (parsed.length === 0) {
      return { data: null, error: 'Array must contain at least one object' }
    }
    if (typeof parsed[0] !== 'object' || parsed[0] === null) {
      return { data: null, error: 'Array items must be objects' }
    }
    return { data: parsed as DataRow[], error: null }
  } catch (e) {
    const message = e instanceof Error ? e.message : 'Invalid JSON'
    return { data: null, error: message }
  }
}

import { h } from 'plaited'
import type { ChartConfig, ParsedChartData } from './types'

const PADDING = { top: 50, right: 30, bottom: 60, left: 60 }

const escapeXml = (str: string): string =>
  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')

const truncateLabel = (label: string, maxLen = 12): string =>
  label.length > maxLen ? `${label.slice(0, maxLen - 1)}…` : label

const computeNiceTicks = (min: number, max: number, targetCount = 5): number[] => {
  if (min === max) return [min]
  const range = max - min
  const roughStep = range / targetCount
  const magnitude = Math.pow(10, Math.floor(Math.log10(roughStep)))
  const residual = roughStep / magnitude
  const niceStep = residual <= 1.5 ? magnitude
    : residual <= 3 ? 2 * magnitude
    : residual <= 7 ? 5 * magnitude
    : 10 * magnitude

  const start = Math.floor(min / niceStep) * niceStep
  const ticks: number[] = []
  for (let v = start; v <= max + niceStep * 0.01; v += niceStep) {
    ticks.push(Math.round(v * 1e10) / 1e10)
  }
  return ticks
}

export const renderBarChart = (data: ParsedChartData, config: ChartConfig): string => {
  const { width, height, title, xLabel, yLabel, colors } = config
  const plotW = width - PADDING.left - PADDING.right
  const plotH = height - PADDING.top - PADDING.bottom

  const allValues = data.series.flatMap((s) => s.values)
  const maxVal = Math.max(...allValues, 0)
  const minVal = Math.min(0, ...allValues)
  const ticks = computeNiceTicks(minVal, maxVal)
  const yMax = ticks[ticks.length - 1]
  const yMin = ticks[0]
  const yRange = yMax - yMin || 1

  const groupCount = data.categories.length
  const seriesCount = data.series.length
  const groupWidth = plotW / groupCount
  const barPadding = groupWidth * 0.15
  const barWidth = (groupWidth - barPadding * 2) / seriesCount

  const scaleY = (v: number) => plotH - ((v - yMin) / yRange) * plotH

  const bars: string[] = []
  data.categories.forEach((_, gi) => {
    data.series.forEach((series, si) => {
      const x = PADDING.left + gi * groupWidth + barPadding + si * barWidth
      const val = series.values[gi]
      const barH = ((val - Math.min(0, yMin)) / yRange) * plotH
      const y = PADDING.top + plotH - barH
      bars.push(
        `<rect x="${x}" y="${y}" width="${barWidth}" height="${barH}" fill="${colors[si % colors.length]}" rx="2"/>`,
      )
    })
  })

  const gridLines = ticks.map((t) => {
    const y = PADDING.top + scaleY(t)
    return `<line x1="${PADDING.left}" x2="${width - PADDING.right}" y1="${y}" y2="${y}" stroke="#e0e0e0" stroke-width="1"/>`
      + `<text x="${PADDING.left - 8}" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${t}</text>`
  }).join('')

  const catLabels = data.categories.map((cat, i) => {
    const x = PADDING.left + i * groupWidth + groupWidth / 2
    const y = PADDING.top + plotH + 18
    return `<text x="${x}" y="${y}" text-anchor="middle" font-size="11" fill="#666">${escapeXml(truncateLabel(cat))}</text>`
  }).join('')

  const legend = data.series.length > 1
    ? data.series.map((s, i) => {
      const lx = PADDING.left + i * 120
      return `<rect x="${lx}" y="${height - 15}" width="12" height="12" fill="${colors[i % colors.length]}" rx="2"/>`
        + `<text x="${lx + 16}" y="${height - 5}" font-size="11" fill="#333">${escapeXml(s.name)}</text>`
    }).join('')
    : ''

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">
    <rect width="${width}" height="${height}" fill="#fff"/>
    ${title ? `<text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="600" fill="#222">${escapeXml(title)}</text>` : ''}
    ${gridLines}
    <line x1="${PADDING.left}" x2="${PADDING.left}" y1="${PADDING.top}" y2="${PADDING.top + plotH}" stroke="#ccc" stroke-width="1"/>
    <line x1="${PADDING.left}" x2="${width - PADDING.right}" y1="${PADDING.top + plotH}" y2="${PADDING.top + plotH}" stroke="#ccc" stroke-width="1"/>
    ${bars.join('')}
    ${catLabels}
    ${xLabel ? `<text x="${width / 2}" y="${PADDING.top + plotH + 45}" text-anchor="middle" font-size="12" fill="#444">${escapeXml(xLabel)}</text>` : ''}
    ${yLabel ? `<text x="16" y="${height / 2}" text-anchor="middle" font-size="12" fill="#444" transform="rotate(-90,16,${height / 2})">${escapeXml(yLabel)}</text>` : ''}
    ${legend}
  </svg>`
}

export const renderLineChart = (data: ParsedChartData, config: ChartConfig): string => {
  const { width, height, title, xLabel, yLabel, colors } = config
  const plotW = width - PADDING.left - PADDING.right
  const plotH = height - PADDING.top - PADDING.bottom

  const allValues = data.series.flatMap((s) => s.values)
  const maxVal = Math.max(...allValues, 0)
  const minVal = Math.min(...allValues, 0)
  const ticks = computeNiceTicks(minVal, maxVal)
  const yMax = ticks[ticks.length - 1]
  const yMin = ticks[0]
  const yRange = yMax - yMin || 1

  const pointCount = data.categories.length
  const xStep = pointCount > 1 ? plotW / (pointCount - 1) : plotW / 2

  const scaleY = (v: number) => PADDING.top + plotH - ((v - yMin) / yRange) * plotH
  const scaleX = (i: number) => PADDING.left + (pointCount > 1 ? i * xStep : plotW / 2)

  const paths = data.series.map((series, si) => {
    const color = colors[si % colors.length]
    const points = series.values.map((v, i) => `${scaleX(i)},${scaleY(v)}`)
    const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p}`).join(' ')
    const dots = series.values.map((v, i) =>
      `<circle cx="${scaleX(i)}" cy="${scaleY(v)}" r="4" fill="${color}" stroke="#fff" stroke-width="1.5"/>`,
    ).join('')
    return `<path d="${pathD}" fill="none" stroke="${color}" stroke-width="2.5" stroke-linejoin="round"/>${dots}`
  }).join('')

  const gridLines = ticks.map((t) => {
    const y = scaleY(t)
    return `<line x1="${PADDING.left}" x2="${width - PADDING.right}" y1="${y}" y2="${y}" stroke="#e0e0e0" stroke-width="1"/>`
      + `<text x="${PADDING.left - 8}" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${t}</text>`
  }).join('')

  const catLabels = data.categories.map((cat, i) => {
    const x = scaleX(i)
    const y = PADDING.top + plotH + 18
    return `<text x="${x}" y="${y}" text-anchor="middle" font-size="11" fill="#666">${escapeXml(truncateLabel(cat))}</text>`
  }).join('')

  const legend = data.series.length > 1
    ? data.series.map((s, i) => {
      const lx = PADDING.left + i * 120
      return `<line x1="${lx}" x2="${lx + 12}" y1="${height - 9}" y2="${height - 9}" stroke="${colors[i % colors.length]}" stroke-width="2.5"/>`
        + `<text x="${lx + 16}" y="${height - 5}" font-size="11" fill="#333">${escapeXml(s.name)}</text>`
    }).join('')
    : ''

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">
    <rect width="${width}" height="${height}" fill="#fff"/>
    ${title ? `<text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="600" fill="#222">${escapeXml(title)}</text>` : ''}
    ${gridLines}
    <line x1="${PADDING.left}" x2="${PADDING.left}" y1="${PADDING.top}" y2="${PADDING.top + plotH}" stroke="#ccc" stroke-width="1"/>
    <line x1="${PADDING.left}" x2="${width - PADDING.right}" y1="${PADDING.top + plotH}" y2="${PADDING.top + plotH}" stroke="#ccc" stroke-width="1"/>
    ${paths}
    ${catLabels}
    ${xLabel ? `<text x="${width / 2}" y="${PADDING.top + plotH + 45}" text-anchor="middle" font-size="12" fill="#444">${escapeXml(xLabel)}</text>` : ''}
    ${yLabel ? `<text x="16" y="${height / 2}" text-anchor="middle" font-size="12" fill="#444" transform="rotate(-90,16,${height / 2})">${escapeXml(yLabel)}</text>` : ''}
    ${legend}
  </svg>`
}

export const renderPieChart = (data: ParsedChartData, config: ChartConfig): string => {
  const { width, height, title, colors } = config

  const values = data.series[0]?.values ?? []
  const total = values.reduce((sum, v) => sum + Math.max(0, v), 0)
  if (total === 0) {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}">
      <text x="${width / 2}" y="${height / 2}" text-anchor="middle" font-size="14" fill="#999">No data to display</text>
    </svg>`
  }

  const cx = width / 2 - 60
  const cy = height / 2 + (title ? 10 : 0)
  const r = Math.min(cx - 20, cy - (title ? 50 : 30)) * 0.85

  let currentAngle = -Math.PI / 2
  const slices: string[] = []
  const labelLines: string[] = []

  values.forEach((val, i) => {
    if (val <= 0) return
    const fraction = val / total
    const sliceAngle = fraction * 2 * Math.PI
    const endAngle = currentAngle + sliceAngle

    const x1 = cx + r * Math.cos(currentAngle)
    const y1 = cy + r * Math.sin(currentAngle)
    const x2 = cx + r * Math.cos(endAngle)
    const y2 = cy + r * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    slices.push(
      `<path d="M${cx},${cy} L${x1},${y1} A${r},${r} 0 ${largeArc} 1 ${x2},${y2} Z" fill="${colors[i % colors.length]}" stroke="#fff" stroke-width="2"/>`,
    )

    const midAngle = currentAngle + sliceAngle / 2
    const labelR = r + 18
    const lx = cx + labelR * Math.cos(midAngle)
    const ly = cy + labelR * Math.sin(midAngle)
    const pct = (fraction * 100).toFixed(1)
    labelLines.push(
      `<text x="${lx}" y="${ly}" text-anchor="${Math.cos(midAngle) < 0 ? 'end' : 'start'}" font-size="10" fill="#555">${pct}%</text>`,
    )

    currentAngle = endAngle
  })

  const legendX = width - 140
  const legendItems = data.categories.map((cat, i) => {
    const ly = 60 + i * 22
    return `<rect x="${legendX}" y="${ly}" width="12" height="12" fill="${colors[i % colors.length]}" rx="2"/>`
      + `<text x="${legendX + 18}" y="${ly + 11}" font-size="11" fill="#333">${escapeXml(truncateLabel(cat, 14))}</text>`
  }).join('')

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">
    <rect width="${width}" height="${height}" fill="#fff"/>
    ${title ? `<text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="600" fill="#222">${escapeXml(title)}</text>` : ''}
    ${slices.join('')}
    ${labelLines.join('')}
    ${legendItems}
  </svg>`
}

export const renderChart = (data: ParsedChartData, config: ChartConfig): string => {
  switch (config.chartType) {
    case 'bar':
      return renderBarChart(data, config)
    case 'line':
      return renderLineChart(data, config)
    case 'pie':
      return renderPieChart(data, config)
  }
}

import { h } from 'plaited'

type TokenType = 'string' | 'number' | 'boolean' | 'null' | 'key' | 'punctuation'

type Token = {
  type: TokenType
  value: string
}

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  let i = 0
  let expectKey = true

  while (i < json.length) {
    const ch = json[i]

    if (/\s/.test(ch)) {
      let ws = ''
      while (i < json.length && /\s/.test(json[i])) {
        ws += json[i]
        i++
      }
      tokens.push({ type: 'punctuation', value: ws })
      continue
    }

    if (ch === '{' || ch === '[') {
      tokens.push({ type: 'punctuation', value: ch })
      expectKey = ch === '{'
      i++
      continue
    }

    if (ch === '}' || ch === ']') {
      tokens.push({ type: 'punctuation', value: ch })
      expectKey = false
      i++
      continue
    }

    if (ch === ',') {
      tokens.push({ type: 'punctuation', value: ch })
      i++
      continue
    }

    if (ch === ':') {
      tokens.push({ type: 'punctuation', value: ch })
      expectKey = false
      i++
      continue
    }

    if (ch === '"') {
      let str = '"'
      i++
      while (i < json.length && json[i] !== '"') {
        if (json[i] === '\\') {
          str += json[i]
          i++
        }
        if (i < json.length) {
          str += json[i]
          i++
        }
      }
      str += '"'
      i++

      const nextNonWs = json.slice(i).match(/^\s*:/)
      if (nextNonWs || expectKey) {
        tokens.push({ type: 'key', value: str })
        expectKey = false
      } else {
        tokens.push({ type: 'string', value: str })
      }
      continue
    }

    if (ch === '-' || /\d/.test(ch)) {
      let num = ''
      while (i < json.length && /[\d.eE+\-]/.test(json[i])) {
        num += json[i]
        i++
      }
      tokens.push({ type: 'number', value: num })
      continue
    }

    if (json.slice(i, i + 4) === 'true') {
      tokens.push({ type: 'boolean', value: 'true' })
      i += 4
      continue
    }

    if (json.slice(i, i + 5) === 'false') {
      tokens.push({ type: 'boolean', value: 'false' })
      i += 5
      continue
    }

    if (json.slice(i, i + 4) === 'null') {
      tokens.push({ type: 'null', value: 'null' })
      i += 4
      continue
    }

    tokens.push({ type: 'punctuation', value: ch })
    i++
  }

  return tokens
}

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#9c27b0',
  string: '#2e7d32',
  number: '#1565c0',
  boolean: '#e65100',
  null: '#757575',
  punctuation: '#37474f',
}

export const highlightJson = (json: string): string => {
  const tokens = tokenize(json)
  return tokens.map((token) => {
    const color = TOKEN_COLORS[token.type]
    const escaped = token.value
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
    if (token.type === 'punctuation') return escaped
    return `<span style="color:${color}">${escaped}</span>`
  }).join('')
}

export const formatJson = (json: string): string => {
  try {
    return JSON.stringify(JSON.parse(json), null, 2)
  } catch {
    return json
  }
}

