  config: ChartConfig
  error: string | null
}

const loadState = async (): Promise<AppState> => {
  try {
    const file = Bun.file(DATA_FILE)
    if (await file.exists()) {
      return await file.json()
    }
  } catch { /* use defaults */ }
  return {
    jsonInput: SAMPLE_DATA,
    config: { ...DEFAULT_CONFIG },
    error: null,
  }
}

const saveState = async (state: AppState): Promise<void> => {
  await Bun.write(DATA_FILE, JSON.stringify(state, null, 2))
}

const autoConfigureFields = (data: DataRow[], config: ChartConfig): ChartConfig => {
  const fields = detectFields(data)
  const updated = { ...config }

  if (!updated.categoryField && fields.categorical.length > 0) {
    updated.categoryField = fields.categorical[0].name
  }
  if (updated.valueFields.length === 0 && fields.numeric.length > 0) {
    updated.valueFields = fields.numeric.map((f) => f.name)
  }

  return updated
}

export const generateChart = (jsonInput: string, config: Partial<ChartConfig> = {}): {
  svg: string
  error: string | null
  detectedFields: ReturnType<typeof detectFields>
} => {
  const { data, error } = validateJsonData(jsonInput)
  if (error || !data) {
    return { svg: '', error: error ?? 'Invalid data', detectedFields: { numeric: [], categorical: [] } }
  }

  const detectedFields = detectFields(data)
  const fullConfig = autoConfigureFields(data, { ...DEFAULT_CONFIG, ...config })
  const chartData = parseChartData(data, fullConfig.categoryField, fullConfig.valueFields)
  const svg = renderChart(chartData, fullConfig)

  return { svg, error: null, detectedFields }
}

export const downloadSvg = (svg: string, filename = 'chart.svg'): string => {
  const blob = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`
  return h('a', {
