export const renderApp = async (): Promise<string> => {
  const state = await loadState()
  const { data } = validateJsonData(state.jsonInput)
  const fields = data ? detectFields(data) : { numeric: [], categorical: [] }

  if (data) {
    state.config = autoConfigureFields(data, state.config)
  }

  const chartResult = data ? generateChart(state.jsonInput, state.config) : null

  const editorHtml = renderJsonEditor(state.jsonInput, state.error)
  const configHtml = data ? renderConfigPanel(state.config, fields) : ''
  const chartHtml = chartResult?.svg ?? ''
  const downloadHtml = chartResult?.svg ? downloadSvg(chartResult.svg) : ''

  return h('div', { style: 'max-width:960px;margin:0 auto;padding:24px;font-family:system-ui,sans-serif;color:#222' },
    h('header', { style: 'margin-bottom:24px' },
      h('h1', { style: 'margin:0 0 4px;font-size:22px;font-weight:700;color:#1a1a1a' }, 'Chart Generator'),
      h('p', { style: 'margin:0;font-size:14px;color:#666' }, 'Paste JSON data below, configure your chart, and download as SVG'),
    ),
    h('section', { style: 'margin-bottom:20px', 'p-target': 'editor-container' },
      h('div', { style: 'display:flex;justify-content:space-between;align-items:center;margin-bottom:8px' },
