        h('button', {
          'p-trigger': 'format-json',
          style: 'padding:4px 10px;border:1px solid #ccc;background:#fff;border-radius:4px;font-size:12px;cursor:pointer;color:#555',
        }, 'Format JSON'),
      ),
      editorHtml,
    ),
    data ? h('section', { style: 'margin-bottom:20px;padding:16px;background:#f9f9f9;border:1px solid #eee;border-radius:6px', 'p-target': 'config-panel' },
      h('h2', { style: 'margin:0 0 12px;font-size:14px;font-weight:600;color:#555;text-transform:uppercase;letter-spacing:0.5px' }, 'Chart Configuration'),
      configHtml,
    ) : '',
    chartHtml ? h('section', { style: 'margin-bottom:20px', 'p-target': 'chart-output' },
      h('div', { style: 'display:flex;justify-content:space-between;align-items:center;margin-bottom:8px' },
        h('h2', { style: 'margin:0;font-size:14px;font-weight:600;color:#555;text-transform:uppercase;letter-spacing:0.5px' }, 'Chart Preview'),
        downloadHtml,
      ),
      h('div', {
