      }, chartHtml),
    ) : '',
  ).toString()
}

export const handleAction = async (action: string, payload?: Record<string, string>): Promise<AppState> => {
  const state = await loadState()

  switch (action) {
    case 'update-json': {
      const input = payload?.value ?? ''
      state.jsonInput = input
      const { data, error } = validateJsonData(input)
      state.error = error
      if (data) {
        state.config = autoConfigureFields(data, state.config)
      }
      break
    }
    case 'format-json': {
      state.jsonInput = formatJson(state.jsonInput)
      break
    }
    case 'select-chart-type': {
      const chartType = payload?.type as ChartConfig['chartType']
      if (['bar', 'line', 'pie'].includes(chartType)) {
        state.config.chartType = chartType
      }
      break
    }
    case 'select-category': {
      state.config.categoryField = payload?.field ?? ''
      break
    }
    case 'toggle-value-field': {
      const field = payload?.field ?? ''
      const idx = state.config.valueFields.indexOf(field)
      if (idx >= 0) {
        state.config.valueFields.splice(idx, 1)
      } else {
        state.config.valueFields.push(field)
      }
      break
    }
    case 'update-title': {
      state.config.title = payload?.value ?? ''
      break
    }
    case 'update-xlabel': {
      state.config.xLabel = payload?.value ?? ''
      break
    }
    case 'update-ylabel': {
      state.config.yLabel = payload?.value ?? ''
      break
    }
    case 'update-color': {
      const index = Number(payload?.index ?? 0)
      const color = payload?.color ?? DEFAULT_COLORS[index]
      if (index >= 0 && index < state.config.colors.length) {
        state.config.colors[index] = color
      }
      break
    }
  }

  await saveState(state)
  return state
}

