  const { html } = createSSR(app)
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Chart Generator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #121212; }
    button:hover { opacity: 0.9; }
    select:focus, input:focus, textarea:focus {
      border-color: #4e79a7 !important;
      outline: none;
    }
  </style>
</head>
<body>${html}</body>
<script>
document.addEventListener('click', (e) => {
  const btn = e.target.closest('[p-trigger*="downloadSvg"]');
  if (!btn) return;
  const container = document.querySelector('[p-target="chartOutput"]');
  if (!container) return;
  const svg = container.querySelector('svg');
  if (!svg) return;
  const serializer = new XMLSerializer();
  const svgStr = '<?xml version="1.0" encoding="UTF-8"?>' + serializer.serializeToString(svg);
  const blob = new Blob([svgStr], { type: 'image/svg+xml;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'chart.svg';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
});
</script>
</html>`
}

const serve = () => {
  let state = createInitialState()

  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (req.method === 'POST' && url.pathname === '/action') {
        const body = await req.json() as { action: string; payload?: string }
        state = handleAction(state, body.action, body.payload)
        return new Response(renderPage(state), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/download') {
        const svg = generateSvgString(state.data, state.config)
        return new Response(svg, {
          headers: {
            'Content-Type': 'image/svg+xml',
            'Content-Disposition': 'attachment; filename="chart.svg"',
          },
        })
      }

      return new Response(renderPage(state), {
        headers: { 'Content-Type': 'text/html' },
      })
    },
  })
}

if (import.meta.main) {
  serve()
}

