273→  const svg = generateSvgString(data, config)
274→  const path = `data/${filename}`
275→  await Bun.write(path, svg)
276→  return path
277→}
278→
279→export const loadDataFromFile = async (path: string): Promise<ChartData> => {
280→  const file = Bun.file(path)
281→  const text = await file.text()
282→  const parsed = parseJsonInput(text)
283→  if (!parsed.valid || !parsed.data) {
284→    throw new Error(parsed.error ?? 'Invalid JSON data')
285→  }
286→  return parsed.data
287→}
288→
289→const serve = () => {
290→  let state = createInitialState()
291→
292→  Bun.serve({
293→    port: 3000,
294→    fetch: async (req) => {
295→      const url = new URL(req.url)
296→
297→      if (req.method === 'POST' && url.pathname === '/action') {
298→        const body = await req.json() as { action: string; payload?: string }
299→        state = handleAction(state, body.action, body.payload)
300→        return new Response(renderPage(state), {
301→          headers: { 'Content-Type': 'text/html' },
302→        })
303→      }
304→
305→      if (url.pathname === '/download') {
306→        const svg = generateSvgString(state.data, state.config)
307→        return new Response(svg, {
308→          headers: {
309→            'Content-Type': 'image/svg+xml',
310→            'Content-Disposition': 'attachment; filename="chart.svg"',
311→          },
312→        })
313→      }
314→
315→      return new Response(renderPage(state), {
316→        headers: { 'Content-Type': 'text/html' },
317→      })
318→    },
319→  })
320→}
321→
322→if (import.meta.main) {
323→  serve()
324→}
325→
326→export { createInitialState, buildConfig, detectFields, parseJsonInput, serve }
327→export type { AppState, ChartConfig, ChartData, ChartType }
