453→          const res = await fetch('/api/search?q=' + encodeURIComponent(q));
454→          const results = await res.json();
455→          const container = document.getElementById('search-results');
456→          if (results.length === 0) {
457→            container.style.display = 'block';
458→            container.innerHTML = '<div style="padding:8px;font-size:12px;color:#666;">No results found</div>';
459→            return;
460→          }
461→          container.style.display = 'block';
462→          container.innerHTML = '';
463→          results.forEach(r => {
464→            const div = document.createElement('div');
465→            div.style.cssText = 'padding:8px;font-size:12px;cursor:pointer;border-radius:4px;margin-bottom:2px;background:#1a1a2e;';
466→            div.textContent = r.displayName;
467→            div.onmouseenter = () => { div.style.background = '#0f3460'; };
468→            div.onmouseleave = () => { div.style.background = '#1a1a2e'; };
469→            div.onclick = () => {
470→              map.setView([r.lat, r.lng], 15);
471→              container.style.display = 'none';
472→              document.getElementById('search-input').value = '';
473→            };
474→            container.appendChild(div);
475→          });
476→        };
477→
478→        document.getElementById('search-btn').onclick = doSearch;
479→        document.getElementById('search-input').onkeydown = (e) => { if (e.key === 'Enter') doSearch(); };
480→
481→        document.addEventListener('click', (e) => {
482→          const sr = document.getElementById('search-results');
483→          if (!sr.contains(e.target) && e.target.id !== 'search-input' && e.target.id !== 'search-btn') {
484→            sr.style.display = 'none';
485→          }
486→        });
487→
488→        initMap();
489→      `),
490→    ),
491→  )
492→
493→  const ssr = createSSR()
494→  return '<!DOCTYPE html>' + ssr(tree)
495→}
