import type { MapMarker, MapCircle, MarkerCategory, StoreData } from './types'

const DATA_DIR = `${import.meta.dir}/../data`

const readJson = async <T>(filename: string): Promise<T> => {
  const file = Bun.file(`${DATA_DIR}/${filename}`)
  const exists = await file.exists()
  if (!exists) {
    await Bun.write(`${DATA_DIR}/${filename}`, '[]')
    return [] as unknown as T
  }
  return file.json() as Promise<T>
}

const writeJson = async <T>(filename: string, data: T): Promise<void> => {
  await Bun.write(`${DATA_DIR}/${filename}`, JSON.stringify(data, null, 2))
}

export const getMarkers = (): Promise<MapMarker[]> => readJson<MapMarker[]>('markers.json')

export const getCircles = (): Promise<MapCircle[]> => readJson<MapCircle[]>('circles.json')

export const getCategories = (): Promise<MarkerCategory[]> => readJson<MarkerCategory[]>('categories.json')

export const getAllData = async (): Promise<StoreData> => {
  const [markers, circles, categories] = await Promise.all([
    getMarkers(),
    getCircles(),
    getCategories(),
  ])
  return { markers, circles, categories }
}

export const addMarker = async (marker: Omit<MapMarker, 'id'>): Promise<MapMarker> => {
  const markers = await getMarkers()
  const newMarker: MapMarker = { ...marker, id: crypto.randomUUID() }
  markers.push(newMarker)
  await writeJson('markers.json', markers)
  return newMarker
}

export const deleteMarker = async (id: string): Promise<boolean> => {
  const markers = await getMarkers()
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await writeJson('markers.json', filtered)
  return true
}

export const addCircle = async (circle: Omit<MapCircle, 'id'>): Promise<MapCircle> => {
  const circles = await getCircles()
  const newCircle: MapCircle = { ...circle, id: crypto.randomUUID() }
  circles.push(newCircle)
  await writeJson('circles.json', circles)
  return newCircle
}

export const deleteCircle = async (id: string): Promise<boolean> => {
  const circles = await getCircles()
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await writeJson('circles.json', filtered)
  return true
}

export const addCategory = async (category: Omit<MarkerCategory, 'id'>): Promise<MarkerCategory> => {
  const categories = await getCategories()
  const newCategory: MarkerCategory = { ...category, id: crypto.randomUUID() }
  categories.push(newCategory)
  await writeJson('categories.json', categories)
  return newCategory
}

