const styleToString = (style: Record<string, string>): string =>
  Object.entries(style)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

export const renderPage = (data: StoreData): string => {
  const { markers, circles, categories } = data

  const categoryMap = new Map(categories.map((c) => [c.id, c]))

  const markersByCategory = new Map<string, typeof markers>()
  for (const marker of markers) {
    const list = markersByCategory.get(marker.categoryId) ?? []
    list.push(marker)
    markersByCategory.set(marker.categoryId, list)
  }

  const categoryOptions = categories
    .map((c) => h('option', { value: c.id }, c.name))

  const filterChips = [
    h('button', {
      class: 'filter-chip active',
      'data-category': 'all',
      onclick: 'filterByCategory("all")',
      style: styleToString(styles.filterChipActive),
    }, 'All'),
    ...categories.map((c) =>
      h('button', {
        class: 'filter-chip',
        'data-category': c.id,
        onclick: `filterByCategory("${c.id}")`,
        style: styleToString(styles.filterChip),
      }, c.name)
    ),
  ]

  const sidebarMarkers = categories.flatMap((cat) => {
    const catMarkers = markersByCategory.get(cat.id)
    if (!catMarkers || catMarkers.length === 0) return []
    return [
      h('div', { class: 'category-label', 'data-category': cat.id, style: styleToString(styles.categoryLabel) },
        `${cat.name} (${catMarkers.length})`
      ),
      ...catMarkers.map((m) =>
        h('div', {
          class: 'marker-item',
          'data-category': m.categoryId,
          'data-marker-id': m.id,
          onclick: `centerOnMarker("${m.id}")`,
          style: `${styleToString(styles.markerItem)};border-left-color:${categoryMap.get(m.categoryId)?.color ?? '#3b82f6'}`,
        },
          h('div', { style: styleToString(styles.markerItemTitle) }, m.title),
          h('div', { style: styleToString(styles.markerItemDesc) }, m.description || 'No description'),
        )
      ),
    ]
  })

  const template = h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Interactive Map'),
      h('link', {
        rel: 'stylesheet',
        href: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',
      }),
      h('script', { src: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js' }, ''),
      h('style', {}, `
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { ${styleToString(styles.page)} }
        .marker-item:hover { background-color: #0f3460 !important; }
        .search-input:focus { border-color: #e94560 !important; }
        .form-input:focus { border-color: #e94560 !important; }
        #map { width: 100%; height: 100%; }
        .leaflet-popup-content-wrapper { border-radius: 8px; }
        .leaflet-popup-content { margin: 12px 16px; }
        .popup-title { font-weight: 600; font-size: 15px; margin-bottom: 4px; }
        .popup-desc { font-size: 13px; color: #666; }
        .popup-category { font-size: 11px; color: #999; text-transform: uppercase; letter-spacing: 0.5px; margin-top: 4px; }
        .form-section { display: none; }
        .form-section.active { display: block; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #1a1a2e; }
        ::-webkit-scrollbar-thumb { background: #0f3460; border-radius: 3px; }
      `),
    ),
    h('body', {},
      h('div', { style: styleToString(styles.sidebar) },
        h('div', { style: styleToString(styles.sidebarHeader) },
          h('h1', { style: styleToString(styles.sidebarTitle) }, 'Interactive Map'),
          h('div', { style: styleToString(styles.searchBar) },
            h('input', {
              type: 'text',
              id: 'search-input',
              class: 'search-input',
              placeholder: 'Search location...',
              style: styleToString(styles.searchInput),
              onkeydown: 'if(event.key==="Enter")searchLocation()',
            }),
            h('button', {
              onclick: 'searchLocation()',
              style: styleToString(styles.searchBtn),
            }, 'Go'),
          ),
        ),
        h('div', { style: styleToString(styles.filterBar) }, ...filterChips),
        h('div', { id: 'marker-list', style: styleToString(styles.markerList) },
          ...(sidebarMarkers.length > 0
            ? sidebarMarkers
            : [h('div', { style: 'padding:24px;text-align:center;color:#a0a0b8;font-size:13px;' }, 'No markers yet. Click the map or use the form below to add one.')]),
        ),
        h('div', { style: `${styleToString(styles.formSection)};flex-shrink:0` },
          h('div', { style: styleToString(styles.tabs) },
            h('button', {
              class: 'form-tab',
              onclick: 'switchTab("marker")',
              id: 'tab-marker',
              style: styleToString(styles.tabActive),
            }, 'Add Marker'),
            h('button', {
              class: 'form-tab',
              onclick: 'switchTab("circle")',
              id: 'tab-circle',
              style: styleToString(styles.tab),
            }, 'Add Circle'),
            h('button', {
              class: 'form-tab',
              onclick: 'switchTab("category")',
              id: 'tab-category',
              style: styleToString(styles.tab),
            }, 'New Category'),
          ),
          h('div', { id: 'form-marker', class: 'form-section active', style: 'padding:10px 0 0' },
            h('div', { style: styleToString(styles.formRow) },
              h('input', { type: 'text', id: 'marker-title', placeholder: 'Title', class: 'form-input', style: styleToString(styles.formInput) }),
            ),
            h('div', { style: styleToString(styles.formRow) },
              h('input', { type: 'text', id: 'marker-desc', placeholder: 'Description', class: 'form-input', style: styleToString(styles.formInput) }),
            ),
            h('div', { style: styleToString(styles.formRow) },
              h('input', { type: 'number', id: 'marker-lat', placeholder: 'Latitude', class: 'form-input', style: styleToString(styles.formInput), step: 'any' }),
              h('input', { type: 'number', id: 'marker-lng', placeholder: 'Longitude', class: 'form-input', style: styleToString(styles.formInput), step: 'any' }),
            ),
            h('div', { style: styleToString(styles.formRow) },
              h('select', { id: 'marker-category', style: styleToString(styles.formSelect) }, ...categoryOptions),
              h('button', { onclick: 'addMarkerFromForm()', style: styleToString(styles.formBtn) }, 'Add Marker'),
            ),
          ),
          h('div', { id: 'form-circle', class: 'form-section', style: 'padding:10px 0 0' },
            h('div', { style: styleToString(styles.formRow) },
              h('input', { type: 'text', id: 'circle-title', placeholder: 'Label', class: 'form-input', style: styleToString(styles.formInput) }),
            ),
            h('div', { style: styleToString(styles.formRow) },
              h('input', { type: 'number', id: 'circle-lat', placeholder: 'Latitude', class: 'form-input', style: styleToString(styles.formInput), step: 'any' }),
              h('input', { type: 'number', id: 'circle-lng', placeholder: 'Longitude', class: 'form-input', style: styleToString(styles.formInput), step: 'any' }),
            ),
            h('div', { style: styleToString(styles.formRow) },
              h('input', { type: 'number', id: 'circle-radius', placeholder: 'Radius (m)', class: 'form-input', style: styleToString(styles.formInput) }),
              h('input', { type: 'color', id: 'circle-color', value: '#e94560', style: 'width:40px;height:32px;border:none;cursor:pointer;background:transparent;' }),
            ),
            h('div', { style: styleToString(styles.formRow) },
              h('button', { onclick: 'addCircleFromForm()', style: styleToString(styles.formBtn) }, 'Add Circle'),
            ),
          ),
          h('div', { id: 'form-category', class: 'form-section', style: 'padding:10px 0 0' },
            h('div', { style: styleToString(styles.formRow) },
              h('input', { type: 'text', id: 'category-name', placeholder: 'Category name', class: 'form-input', style: styleToString(styles.formInput) }),
              h('input', { type: 'color', id: 'category-color', value: '#3b82f6', style: 'width:40px;height:32px;border:none;cursor:pointer;background:transparent;' }),
            ),
            h('div', { style: styleToString(styles.formRow) },
              h('button', { onclick: 'addCategoryFromForm()', style: styleToString(styles.formBtn) }, 'Add Category'),
            ),
          ),
        ),
      ),
      h('div', { style: styleToString(styles.mapContainer) },
        h('div', { id: 'map' }, ''),
      ),
      h('script', {}, `
        const markersData = ${JSON.stringify(markers)};
        const circlesData = ${JSON.stringify(circles)};
        const categoriesData = ${JSON.stringify(categories)};

        const categoryColors = {};
        categoriesData.forEach(c => categoryColors[c.id] = c.color);
        const categoryNames = {};
        categoriesData.forEach(c => categoryNames[c.id] = c.name);

        const map = L.map('map').setView([40.7128, -74.006], 4);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
          maxZoom: 19,
        }).addTo(map);

        const markerLayers = {};
        const circleLayers = {};

        const createColorIcon = (color) => {
          const svg = \`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 36" width="28" height="42">
            <path d="M12 0C5.4 0 0 5.4 0 12c0 9 12 24 12 24s12-15 12-24C24 5.4 18.6 0 12 0z" fill="\${color}" stroke="#fff" stroke-width="1.5"/>
            <circle cx="12" cy="12" r="5" fill="#fff" opacity="0.9"/>
          </svg>\`;
          return L.icon({
            iconUrl: 'data:image/svg+xml;base64,' + btoa(svg),
            iconSize: [28, 42],
            iconAnchor: [14, 42],
            popupAnchor: [0, -42],
          });
        };

        const addMarkerToMap = (m) => {
          const color = categoryColors[m.categoryId] || '#3b82f6';
          const catName = categoryNames[m.categoryId] || 'General';
          const marker = L.marker([m.lat, m.lng], { icon: createColorIcon(color) })
            .addTo(map)
            .bindPopup(
              '<div class="popup-title">' + escapeHtml(m.title) + '</div>' +
              '<div class="popup-desc">' + escapeHtml(m.description || '') + '</div>' +
              '<div class="popup-category">' + escapeHtml(catName) + '</div>' +
              '<div style="margin-top:8px"><button onclick="deleteMarker(\\\'' + m.id + '\\\')" style="background:#e94560;color:#fff;border:none;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:12px;">Delete</button></div>'
            );
          markerLayers[m.id] = marker;
        };

        const addCircleToMap = (c) => {
          const circle = L.circle([c.lat, c.lng], {
            radius: c.radius,
            color: c.color,
            fillColor: c.color,
            fillOpacity: c.fillOpacity || 0.2,
            weight: 2,
          })
            .addTo(map)
            .bindPopup(
              '<div class="popup-title">' + escapeHtml(c.title) + '</div>' +
              '<div class="popup-desc">Radius: ' + c.radius + 'm</div>' +
              '<div style="margin-top:8px"><button onclick="deleteCircleItem(\\\'' + c.id + '\\\')" style="background:#e94560;color:#fff;border:none;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:12px;">Delete</button></div>'
            );
          circleLayers[c.id] = circle;
        };

        const escapeHtml = (str) => {
          const d = document.createElement('div');
          d.textContent = str;
          return d.innerHTML;
        };

        markersData.forEach(addMarkerToMap);
        circlesData.forEach(addCircleToMap);

        if (markersData.length > 0) {
          const group = L.featureGroup(Object.values(markerLayers));
          map.fitBounds(group.getBounds().pad(0.2));
        }

        // Map click to populate lat/lng
        map.on('click', (e) => {
          const latEl = document.getElementById('marker-lat');
          const lngEl = document.getElementById('marker-lng');
          if (latEl && lngEl) {
            latEl.value = e.latlng.lat.toFixed(6);
            lngEl.value = e.latlng.lng.toFixed(6);
          }
          const cLatEl = document.getElementById('circle-lat');
          const cLngEl = document.getElementById('circle-lng');
          if (cLatEl && cLngEl) {
            cLatEl.value = e.latlng.lat.toFixed(6);
            cLngEl.value = e.latlng.lng.toFixed(6);
          }
        });

        const centerOnMarker = (id) => {
          const layer = markerLayers[id];
          if (layer) {
            map.flyTo(layer.getLatLng(), 14, { duration: 0.8 });
            layer.openPopup();
          }
        };

        const filterByCategory = (categoryId) => {
          document.querySelectorAll('.filter-chip').forEach(el => {
            el.style.cssText = el.dataset.category === categoryId
              ? '${styleToString(styles.filterChipActive)}'
              : '${styleToString(styles.filterChip)}';
            if (el.dataset.category === categoryId) el.classList.add('active');
            else el.classList.remove('active');
          });

          document.querySelectorAll('.marker-item, .category-label').forEach(el => {
            if (categoryId === 'all' || el.dataset.category === categoryId) {
              el.style.display = '';
            } else {
              el.style.display = 'none';
            }
          });

          Object.entries(markerLayers).forEach(([id, layer]) => {
            const m = markersData.find(mk => mk.id === id);
            if (categoryId === 'all' || (m && m.categoryId === categoryId)) {
              layer.addTo(map);
            } else {
              map.removeLayer(layer);
            }
          });
        };

        const searchLocation = async () => {
          const q = document.getElementById('search-input').value.trim();
          if (!q) return;
          try {
            const res = await fetch('/api/search?q=' + encodeURIComponent(q));
            const data = await res.json();
            if (data.lat && data.lng) {
              map.flyTo([data.lat, data.lng], 13, { duration: 1.2 });
            } else {
              alert('Location not found');
            }
          } catch (e) {
            alert('Search failed: ' + e.message);
          }
        };

        const addMarkerFromForm = async () => {
          const title = document.getElementById('marker-title').value.trim();
          const description = document.getElementById('marker-desc').value.trim();
          const lat = parseFloat(document.getElementById('marker-lat').value);
          const lng = parseFloat(document.getElementById('marker-lng').value);
          const categoryId = document.getElementById('marker-category').value;
          if (!title || isNaN(lat) || isNaN(lng)) {
            alert('Please provide a title, latitude, and longitude');
            return;
          }
          const res = await fetch('/api/markers', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title, description, lat, lng, categoryId }),
          });
          if (res.ok) location.reload();
        };

        const addCircleFromForm = async () => {
          const title = document.getElementById('circle-title').value.trim();
          const lat = parseFloat(document.getElementById('circle-lat').value);
          const lng = parseFloat(document.getElementById('circle-lng').value);
          const radius = parseFloat(document.getElementById('circle-radius').value);
          const color = document.getElementById('circle-color').value;
          if (!title || isNaN(lat) || isNaN(lng) || isNaN(radius)) {
            alert('Please provide a label, lat, lng, and radius');
            return;
          }
          const res = await fetch('/api/circles', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title, lat, lng, radius, color, fillOpacity: 0.2 }),
          });
          if (res.ok) location.reload();
        };

        const addCategoryFromForm = async () => {
          const name = document.getElementById('category-name').value.trim();
          const color = document.getElementById('category-color').value;
          if (!name) { alert('Please provide a category name'); return; }
          const res = await fetch('/api/categories', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, color }),
          });
          if (res.ok) location.reload();
        };

        const deleteMarker = async (id) => {
          if (!confirm('Delete this marker?')) return;
          const res = await fetch('/api/markers/' + id, { method: 'DELETE' });
          if (res.ok) location.reload();
        };

        const deleteCircleItem = async (id) => {
          if (!confirm('Delete this circle?')) return;
          const res = await fetch('/api/circles/' + id, { method: 'DELETE' });
          if (res.ok) location.reload();
        };

        const switchTab = (tab) => {
          document.querySelectorAll('.form-section').forEach(el => el.classList.remove('active'));
          document.querySelectorAll('.form-tab').forEach(el => {
            el.style.cssText = '${styleToString(styles.tab)}';
          });
          document.getElementById('form-' + tab).classList.add('active');
          const tabEl = document.getElementById('tab-' + tab);
          tabEl.style.cssText = '${styleToString(styles.tabActive)}';
        };
      `),
    ),
  )

  const ssr = createSSR()
  return '<!DOCTYPE html>' + ssr(template)
}

import * as store from './store'
import { renderPage } from './render'
import type { SearchResult } from './types'

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (body: string) =>
  new Response(body, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleIndex = async (): Promise<Response> => {
  const data = await store.getAllData()
  return html(renderPage(data))
}

export const handleGetMarkers = async (): Promise<Response> => {
  const markers = await store.getMarkers()
  return json(markers)
}

export const handleCreateMarker = async (req: Request): Promise<Response> => {
  const body = await req.json()
  const { title, description, lat, lng, categoryId } = body
  if (!title || typeof lat !== 'number' || typeof lng !== 'number') {
    return json({ error: 'title, lat, and lng are required' }, 400)
  }
  const marker = await store.addMarker({
    title,
    description: description ?? '',
    lat,
    lng,
    categoryId: categoryId ?? 'default',
  })
  return json(marker, 201)
}

export const handleDeleteMarker = async (id: string): Promise<Response> => {
  const deleted = await store.deleteMarker(id)
  if (!deleted) return json({ error: 'Marker not found' }, 404)
  return json({ ok: true })
}

export const handleGetCircles = async (): Promise<Response> => {
  const circles = await store.getCircles()
  return json(circles)
}

export const handleCreateCircle = async (req: Request): Promise<Response> => {
  const body = await req.json()
  const { title, lat, lng, radius, color, fillOpacity } = body
  if (!title || typeof lat !== 'number' || typeof lng !== 'number' || typeof radius !== 'number') {
    return json({ error: 'title, lat, lng, and radius are required' }, 400)
  }
  const circle = await store.addCircle({
    title,
    lat,
    lng,
    radius,
    color: color ?? '#e94560',
    fillOpacity: fillOpacity ?? 0.2,
  })
  return json(circle, 201)
}

export const handleDeleteCircle = async (id: string): Promise<Response> => {
  const deleted = await store.deleteCircle(id)
  if (!deleted) return json({ error: 'Circle not found' }, 404)
  return json({ ok: true })
}

export const handleGetCategories = async (): Promise<Response> => {
  const categories = await store.getCategories()
  return json(categories)
}

export const handleCreateCategory = async (req: Request): Promise<Response> => {
  const body = await req.json()
  const { name, color } = body
  if (!name || !color) {
    return json({ error: 'name and color are required' }, 400)
  }
  const category = await store.addCategory({ name, color })
  return json(category, 201)
}

export const handleSearch = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const q = url.searchParams.get('q')
  if (!q) return json({ error: 'q parameter is required' }, 400)

  const nominatimUrl = `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(q)}&limit=1`
  const res = await fetch(nominatimUrl, {
    headers: { 'User-Agent': 'interactive-map-module/1.0' },
  })
  const results = await res.json() as Array<{ lat: string; lon: string; display_name: string }>

  if (results.length === 0) {
    return json({ error: 'Location not found' }, 404)
  }

  const result: SearchResult = {
    lat: parseFloat(results[0].lat),
    lng: parseFloat(results[0].lon),
    displayName: results[0].display_name,
  }
  return json(result)
}

import {
  handleIndex,
  handleGetMarkers,
  handleCreateMarker,
  handleDeleteMarker,
  handleGetCircles,
  handleCreateCircle,
  handleDeleteCircle,
  handleGetCategories,
  handleCreateCategory,
  handleSearch,
} from './handlers'

type RouteHandler = (req: Request, params?: Record<string, string>) => Promise<Response>

type Route = {
  method: string
  pattern: RegExp
  handler: RouteHandler
  paramNames: string[]
}

const routes: Route[] = [
  { method: 'GET', pattern: /^\/$/, handler: handleIndex, paramNames: [] },
  { method: 'GET', pattern: /^\/api\/markers$/, handler: handleGetMarkers, paramNames: [] },
  { method: 'POST', pattern: /^\/api\/markers$/, handler: handleCreateMarker, paramNames: [] },
  { method: 'DELETE', pattern: /^\/api\/markers\/([^/]+)$/, handler: (_, p) => handleDeleteMarker(p!.id), paramNames: ['id'] },
  { method: 'GET', pattern: /^\/api\/circles$/, handler: handleGetCircles, paramNames: [] },
  { method: 'POST', pattern: /^\/api\/circles$/, handler: handleCreateCircle, paramNames: [] },
  { method: 'DELETE', pattern: /^\/api\/circles\/([^/]+)$/, handler: (_, p) => handleDeleteCircle(p!.id), paramNames: ['id'] },
  { method: 'GET', pattern: /^\/api\/categories$/, handler: handleGetCategories, paramNames: [] },
  { method: 'POST', pattern: /^\/api\/categories$/, handler: handleCreateCategory, paramNames: [] },
  { method: 'GET', pattern: /^\/api\/search$/, handler: handleSearch, paramNames: [] },
]

const matchRoute = (method: string, pathname: string): { handler: RouteHandler; params: Record<string, string> } | null => {
  for (const route of routes) {
    if (route.method !== method) continue
    const match = pathname.match(route.pattern)
    if (match) {
      const params: Record<string, string> = {}
      route.paramNames.forEach((name, i) => {
        params[name] = match[i + 1]
      })
      return { handler: route.handler, params }
    }
  }
  return null
}

export const serve = (options: { port?: number } = {}) => {
  const port = options.port ?? 3000

  const server = Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)
      const matched = matchRoute(req.method, url.pathname)

      if (!matched) {
        return new Response(JSON.stringify({ error: 'Not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' },
        })
      }

      try {
        return await matched.handler(req, matched.params)
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Internal server error'
        return new Response(JSON.stringify({ error: message }), {
          status: 500,
          headers: { 'Content-Type': 'application/json' },
        })
      }
    },
  })

  console.log(`Interactive Map running at http://localhost:${server.port}`)
  return server
}

