import type { MapData, MapMarker, MapCircle, MarkerCategory } from './types'

const DATA_PATH = './data/map-data.json'

const DEFAULT_CATEGORIES: MarkerCategory[] = [
  { id: 'default', name: 'General', color: '#2196F3' },
  { id: 'food', name: 'Food & Drink', color: '#FF9800' },
  { id: 'nature', name: 'Nature', color: '#4CAF50' },
  { id: 'culture', name: 'Culture', color: '#9C27B0' },
  { id: 'danger', name: 'Warning', color: '#F44336' },
]

const generateId = (): string => crypto.randomUUID()

const loadData = async (): Promise<MapData> => {
  try {
    const file = Bun.file(DATA_PATH)
    const exists = await file.exists()
    if (!exists) {
      const initial: MapData = { markers: [], circles: [], categories: DEFAULT_CATEGORIES }
      await Bun.write(DATA_PATH, JSON.stringify(initial, null, 2))
      return initial
    }
    return await file.json()
  } catch {
    const initial: MapData = { markers: [], circles: [], categories: DEFAULT_CATEGORIES }
    await Bun.write(DATA_PATH, JSON.stringify(initial, null, 2))
    return initial
  }
}

const saveData = async (data: MapData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const getMarkers = async (): Promise<MapMarker[]> => {
  const data = await loadData()
  return data.markers
}

export const addMarker = async (marker: Omit<MapMarker, 'id'>): Promise<MapMarker> => {
  const data = await loadData()
  const newMarker: MapMarker = { id: generateId(), ...marker }
  data.markers.push(newMarker)
  await saveData(data)
  return newMarker
}

export const deleteMarker = async (id: string): Promise<boolean> => {
  const data = await loadData()
  const idx = data.markers.findIndex((m) => m.id === id)
  if (idx === -1) return false
  data.markers.splice(idx, 1)
  await saveData(data)
  return true
}

export const getCircles = async (): Promise<MapCircle[]> => {
  const data = await loadData()
  return data.circles
}

export const addCircle = async (circle: Omit<MapCircle, 'id'>): Promise<MapCircle> => {
  const data = await loadData()
  const newCircle: MapCircle = { id: generateId(), ...circle }
  data.circles.push(newCircle)
  await saveData(data)
  return newCircle
}

export const deleteCircle = async (id: string): Promise<boolean> => {
  const data = await loadData()
  const idx = data.circles.findIndex((c) => c.id === id)
  if (idx === -1) return false
  data.circles.splice(idx, 1)
  await saveData(data)
  return true
}

export const getCategories = async (): Promise<MarkerCategory[]> => {
  const data = await loadData()
  return data.categories
}

export const addCategory = async (category: Omit<MarkerCategory, 'id'>): Promise<MarkerCategory> => {
  const data = await loadData()
  const newCat: MarkerCategory = { id: generateId(), ...category }
  data.categories.push(newCat)
  await saveData(data)
  return newCat
}

export const deleteCategory = async (id: string): Promise<boolean> => {
  const data = await loadData()
  const idx = data.categories.findIndex((c) => c.id === id)
  if (idx === -1) return false
  data.categories.splice(idx, 1)
  data.markers = data.markers.filter((m) => m.category !== id)
  await saveData(data)
  return true
}

export const getAllData = async (): Promise<MapData> => {
  return loadData()
}

