    .join(';')

export const renderPage = (data: MapData): string => {
  const categoryOptions = data.categories.map((cat) =>
    h('option', { value: cat.id }, cat.name)
  )

  const categoryBadges = data.categories.map((cat) =>
    h(
      'label',
      { style: styleToString(styles.categoryBadge) },
      h('input', {
        type: 'checkbox',
        checked: 'true',
        'data-category-id': cat.id,
        onchange: 'toggleCategory(this)',
        style: 'display:none',
      }),
      h('span', {
        style: styleToString({ ...styles.colorDot, backgroundColor: cat.color }),
      }),
      cat.name
    )
  )

  const markersByCategory = new Map<string, typeof data.markers>()
  for (const marker of data.markers) {
    const list = markersByCategory.get(marker.category) ?? []
    list.push(marker)
    markersByCategory.set(marker.category, list)
  }

  const markerSections = data.categories
    .filter((cat) => markersByCategory.has(cat.id))
    .map((cat) => {
      const markers = markersByCategory.get(cat.id) ?? []
      return h(
        Fragment,
