import {
  getMarkers,
  addMarker,
  deleteMarker,
  getCircles,
  addCircle,
  deleteCircle,
  getCategories,
  addCategory,
  deleteCategory,
  getAllData,
} from './data'
import { renderPage } from './render'
import type { SearchResult } from './types'

const NOMINATIM_URL = 'https://nominatim.openstreetmap.org/search'

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const searchLocation = async (query: string): Promise<SearchResult | null> => {
  const url = `${NOMINATIM_URL}?q=${encodeURIComponent(query)}&format=json&limit=1`
  const res = await fetch(url, {
    headers: { 'User-Agent': 'interactive-map-module/1.0' },
  })
  if (!res.ok) return null
  const results = (await res.json()) as Array<{ lat: string; lon: string; display_name: string }>
  if (results.length === 0) return null
  return {
    lat: parseFloat(results[0].lat),
    lng: parseFloat(results[0].lon),
    displayName: results[0].display_name,
  }
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Serve main page
    if (path === '/' && method === 'GET') {
      const data = await getAllData()
      const html = renderPage(data)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Markers API
    if (path === '/api/markers' && method === 'GET') {
      return jsonResponse(await getMarkers())
    }

    if (path === '/api/markers' && method === 'POST') {
      const body = await req.json()
      const { title, description = '', lat, lng, category = 'default' } = body
      if (!title || lat == null || lng == null) {
        return jsonResponse({ error: 'title, lat, lng required' }, 400)
      }
      const marker = await addMarker({ title, description, lat: Number(lat), lng: Number(lng), category })
      return jsonResponse(marker, 201)
    }

    if (path.startsWith('/api/markers/') && method === 'DELETE') {
      const id = path.split('/api/markers/')[1]
      const ok = await deleteMarker(id)
      return ok ? jsonResponse({ ok: true }) : jsonResponse({ error: 'not found' }, 404)
    }

    // Circles API
    if (path === '/api/circles' && method === 'GET') {
      return jsonResponse(await getCircles())
    }

    if (path === '/api/circles' && method === 'POST') {
      const body = await req.json()
      const { label, lat, lng, radius, color = '#e94560' } = body
      if (!label || lat == null || lng == null || radius == null) {
        return jsonResponse({ error: 'label, lat, lng, radius required' }, 400)
      }
      const circle = await addCircle({ label, lat: Number(lat), lng: Number(lng), radius: Number(radius), color })
      return jsonResponse(circle, 201)
    }

    if (path.startsWith('/api/circles/') && method === 'DELETE') {
      const id = path.split('/api/circles/')[1]
      const ok = await deleteCircle(id)
      return ok ? jsonResponse({ ok: true }) : jsonResponse({ error: 'not found' }, 404)
    }

    // Categories API
    if (path === '/api/categories' && method === 'GET') {
      return jsonResponse(await getCategories())
    }

    if (path === '/api/categories' && method === 'POST') {
      const body = await req.json()
      const { name, color } = body
      if (!name || !color) {
        return jsonResponse({ error: 'name, color required' }, 400)
      }
      const cat = await addCategory({ name, color })
      return jsonResponse(cat, 201)
    }

    if (path.startsWith('/api/categories/') && method === 'DELETE') {
      const id = path.split('/api/categories/')[1]
      const ok = await deleteCategory(id)
      return ok ? jsonResponse({ ok: true }) : jsonResponse({ error: 'not found' }, 404)
    }

    // Search API
    if (path === '/api/search' && method === 'GET') {
      const q = url.searchParams.get('q')
      if (!q) return jsonResponse({ error: 'q parameter required' }, 400)
      const result = await searchLocation(q)
      if (!result) return jsonResponse({ error: 'location not found' }, 404)
      return jsonResponse(result)
    }

    return jsonResponse({ error: 'not found' }, 404)
  },
})

