311→const clientScript = (markers: MapMarker[], circles: MapCircle[]): string => `
312→(function() {
313→  var CATEGORY_COLORS = ${JSON.stringify(Object.fromEntries(CATEGORIES.map((c) => [c.name, c.color])))};
314→
315→  var map = L.map('map').setView([40.7128, -74.006], 12);
316→  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
317→    attribution: '&copy; OpenStreetMap contributors',
318→    maxZoom: 19,
319→  }).addTo(map);
320→
321→  var markerLayer = L.layerGroup().addTo(map);
322→  var circleLayer = L.layerGroup().addTo(map);
323→  var leafletMarkers = {};
324→  var leafletCircles = {};
325→  var activeFilters = new Set(${JSON.stringify(CATEGORIES.map((c) => c.name))});
326→
327→  function createColorIcon(color) {
328→    return L.divIcon({
329→      className: '',
330→      html: '<div style="width:24px;height:24px;border-radius:50% 50% 50% 0;background:' + color + ';transform:rotate(-45deg);border:2px solid #fff;box-shadow:0 1px 4px rgba(0,0,0,0.3);"></div>',
331→      iconSize: [24, 24],
332→      iconAnchor: [12, 24],
333→      popupAnchor: [0, -24],
334→    });
335→  }
336→
337→  function addMarkerToMap(m) {
338→    var icon = createColorIcon(CATEGORY_COLORS[m.category] || '#2196F3');
339→    var lm = L.marker([m.lat, m.lng], { icon: icon })
340→      .bindPopup('<strong>' + escapeHtml(m.title) + '</strong>' + (m.description ? '<br>' + escapeHtml(m.description) : '') + '<br><em style="color:' + (CATEGORY_COLORS[m.category] || '#2196F3') + '">' + m.category + '</em>');
341→    markerLayer.addLayer(lm);
342→    leafletMarkers[m.id] = lm;
343→    if (!activeFilters.has(m.category)) lm.remove();
344→  }
345→
346→  function addCircleToMap(c) {
347→    var lc = L.circle([c.lat, c.lng], {
348→      radius: c.radius,
349→      color: c.color || '#2196F3',
350→      fillOpacity: 0.15,
351→      weight: 2,
352→    });
353→    if (c.label) lc.bindPopup(escapeHtml(c.label));
354→    circleLayer.addLayer(lc);
355→    leafletCircles[c.id] = lc;
356→  }
357→
358→  function escapeHtml(s) {
359→    var d = document.createElement('div');
360→    d.textContent = s;
361→    return d.innerHTML;
362→  }
363→
364→  // Init existing data
365→  var initMarkers = ${JSON.stringify(markers)};
366→  var initCircles = ${JSON.stringify(circles)};
367→  initMarkers.forEach(addMarkerToMap);
368→  initCircles.forEach(addCircleToMap);
369→
370→  // Click-to-center from sidebar
371→  document.getElementById('marker-list').addEventListener('click', function(e) {
372→    var item = e.target.closest('.marker-item');
373→    if (!item) return;
374→    if (e.target.closest('.delete-btn')) {
375→      var delId = e.target.closest('.delete-btn').dataset.deleteId;
376→      fetch('/api/markers/' + delId, { method: 'DELETE' }).then(function() { location.reload(); });
377→      return;
378→    }
379→    var lat = parseFloat(item.dataset.lat);
380→    var lng = parseFloat(item.dataset.lng);
381→    map.flyTo([lat, lng], 16);
382→    var lm = leafletMarkers[item.dataset.markerId];
383→    if (lm) lm.openPopup();
384→  });
385→
386→  // Category filtering
387→  document.getElementById('filter-row').addEventListener('click', function(e) {
388→    var chip = e.target.closest('.filter-chip');
389→    if (!chip) return;
390→    var cat = chip.dataset.category;
391→    if (activeFilters.has(cat)) {
392→      activeFilters.delete(cat);
393→      chip.style.backgroundColor = '#fff';
394→      chip.style.color = CATEGORY_COLORS[cat];
395→    } else {
396→      activeFilters.add(cat);
397→      chip.style.backgroundColor = CATEGORY_COLORS[cat];
398→      chip.style.color = '#fff';
399→    }
400→    // Show/hide markers
401→    Object.keys(leafletMarkers).forEach(function(id) {
402→      var markerEl = document.querySelector('[data-marker-id="' + id + '"]');
403→      if (!markerEl) return;
404→      var mCat = markerEl.dataset.category;
405→      if (activeFilters.has(mCat)) {
406→        markerLayer.addLayer(leafletMarkers[id]);
407→        markerEl.style.display = '';
408→      } else {
409→        markerLayer.removeLayer(leafletMarkers[id]);
410→        markerEl.style.display = 'none';
411→      }
412→    });
413→    // Show/hide sections
414→    document.querySelectorAll('#marker-list > div').forEach(function(div) {
415→      if (div.style && div.style.textTransform === 'uppercase') {
416→        // section header - check if next siblings are visible
417→      }
418→    });
419→  });
420→
421→  // Search location
422→  document.getElementById('search-btn').addEventListener('click', doSearch);
423→  document.getElementById('search-input').addEventListener('keydown', function(e) {
424→    if (e.key === 'Enter') doSearch();
425→  });
426→  function doSearch() {
427→    var q = document.getElementById('search-input').value.trim();
428→    if (!q) return;
429→    fetch('/api/search?q=' + encodeURIComponent(q))
430→      .then(function(r) { return r.json(); })
431→      .then(function(results) {
432→        if (results.length > 0) {
433→          map.flyTo([parseFloat(results[0].lat), parseFloat(results[0].lon)], 14);
434→        } else {
435→          alert('Location not found');
436→        }
437→      })
438→      .catch(function() { alert('Search failed'); });
439→  }
440→
441→  // Add marker flow
442→  var pendingMarker = null;
443→  var pendingCircle = null;
444→  var overlay = document.getElementById('modal-overlay');
445→  var markerModal = document.getElementById('marker-modal');
446→  var circleModal = document.getElementById('circle-modal');
447→
448→  document.getElementById('add-marker-btn').addEventListener('click', function() {
449→    markerModal.style.display = '';
450→    circleModal.style.display = 'none';
451→    overlay.classList.add('active');
452→  });
453→
454→  document.getElementById('add-circle-btn').addEventListener('click', function() {
455→    markerModal.style.display = 'none';
456→    circleModal.style.display = '';
457→    overlay.classList.add('active');
458→  });
459→
460→  function closeModal() {
461→    overlay.classList.remove('active');
462→    pendingMarker = null;
463→    pendingCircle = null;
464→  }
465→
466→  document.getElementById('modal-cancel').addEventListener('click', closeModal);
467→  document.getElementById('circle-cancel').addEventListener('click', closeModal);
468→  overlay.addEventListener('click', function(e) { if (e.target === overlay) closeModal(); });
469→
470→  document.getElementById('modal-submit').addEventListener('click', function() {
471→    var title = document.getElementById('marker-title').value.trim();
472→    if (!title) { alert('Title is required'); return; }
473→    pendingMarker = {
474→      title: title,
475→      description: document.getElementById('marker-desc').value.trim(),
476→      category: document.getElementById('marker-cat').value,
477→    };
478→    overlay.classList.remove('active');
479→    map.getContainer().style.cursor = 'crosshair';
480→  });
481→
482→  document.getElementById('circle-submit').addEventListener('click', function() {
483→    var radius = parseInt(document.getElementById('circle-radius').value, 10);
484→    if (!radius || radius < 50) { alert('Radius must be at least 50m'); return; }
485→    pendingCircle = {
486→      label: document.getElementById('circle-label').value.trim(),
487→      radius: radius,
488→      color: document.getElementById('circle-color').value,
489→    };
490→    overlay.classList.remove('active');
491→    map.getContainer().style.cursor = 'crosshair';
492→  });
493→
494→  map.on('click', function(e) {
495→    if (pendingMarker) {
496→      var body = Object.assign({}, pendingMarker, { lat: e.latlng.lat, lng: e.latlng.lng });
497→      fetch('/api/markers', {
498→        method: 'POST',
499→        headers: { 'Content-Type': 'application/json' },
500→        body: JSON.stringify(body),
501→      })
502→        .then(function(r) { return r.json(); })
503→        .then(function(m) {
504→          addMarkerToMap(m);
505→          location.reload();
506→        });
507→      pendingMarker = null;
508→      map.getContainer().style.cursor = '';
509→    } else if (pendingCircle) {
510→      var cbody = Object.assign({}, pendingCircle, { lat: e.latlng.lat, lng: e.latlng.lng });
511→      fetch('/api/circles', {
512→        method: 'POST',
513→        headers: { 'Content-Type': 'application/json' },
514→        body: JSON.stringify(cbody),
515→      })
516→        .then(function(r) { return r.json(); })
517→        .then(function(c) {
518→          addCircleToMap(c);
519→          location.reload();
520→        });
521→      pendingCircle = null;
522→      map.getContainer().style.cursor = '';
523→    }
524→  });
525→})();
526→`;
