 1→import {
 2→  handleGetIndex,
 3→  handleGetMarkers,
 4→  handlePostMarker,
 5→  handleDeleteMarker,
 6→  handleGetCircles,
 7→  handlePostCircle,
 8→  handleDeleteCircle,
 9→  handleSearch,
10→} from './handlers';
11→
12→const PORT = Number(process.env.PORT) || 3000;
13→
14→const router = async (req: Request): Promise<Response> => {
15→  const url = new URL(req.url);
16→  const { pathname } = url;
17→  const method = req.method;
18→
19→  // Page
20→  if (pathname === '/' && method === 'GET') {
21→    return handleGetIndex();
22→  }
23→
24→  // Markers API
25→  if (pathname === '/api/markers' && method === 'GET') {
26→    return handleGetMarkers(url);
27→  }
28→  if (pathname === '/api/markers' && method === 'POST') {
29→    return handlePostMarker(req);
30→  }
31→  const markerDeleteMatch = pathname.match(/^\/api\/markers\/([^/]+)$/);
32→  if (markerDeleteMatch && method === 'DELETE') {
33→    return handleDeleteMarker(markerDeleteMatch[1]);
34→  }
35→
36→  // Circles API
37→  if (pathname === '/api/circles' && method === 'GET') {
38→    return handleGetCircles();
39→  }
40→  if (pathname === '/api/circles' && method === 'POST') {
41→    return handlePostCircle(req);
42→  }
43→  const circleDeleteMatch = pathname.match(/^\/api\/circles\/([^/]+)$/);
44→  if (circleDeleteMatch && method === 'DELETE') {
45→    return handleDeleteCircle(circleDeleteMatch[1]);
46→  }
47→
48→  // Search
49→  if (pathname === '/api/search' && method === 'GET') {
50→    return handleSearch(url);
51→  }
52→
53→  return new Response('Not Found', { status: 404 });
54→};
55→
56→Bun.serve({
57→  port: PORT,
58→  fetch: router,
59→});
60→
61→console.log(`Interactive Map running at http://localhost:${PORT}`);
