 3→export const CATEGORIES: CategoryColor[] = [
 4→  { name: 'general', label: 'General', color: '#2196F3' },
 5→  { name: 'food', label: 'Food', color: '#4CAF50' },
 6→  { name: 'landmark', label: 'Landmark', color: '#FF9800' },
 7→  { name: 'warning', label: 'Warning', color: '#F44336' },
