11→export const getCategoryColor = (category: MarkerCategory): string => {
12→  const found = CATEGORIES.find((c) => c.name === category);
13→  return found?.color ?? '#2196F3';
14→};
15→
16→export const getCategoryLabel = (category: MarkerCategory): string => {
17→  const found = CATEGORIES.find((c) => c.name === category);
18→  return found?.label ?? 'General';
