  1→import { getMarkers, addMarker, deleteMarker, getCircles, addCircle, deleteCircle } from './store';
  2→import { renderPage } from './render';
  3→import type { MapMarker, MapCircle, MarkerCategory, NominatimResult } from './types';
  4→import { CATEGORIES } from './categories';
  5→
  6→const generateId = (): string => crypto.randomUUID();
  7→
  8→const jsonResponse = (data: unknown, status = 200): Response =>
  9→  new Response(JSON.stringify(data), {
 10→    status,
 11→    headers: { 'Content-Type': 'application/json' },
 12→  });
 13→
 14→const validCategories = new Set<string>(CATEGORIES.map((c) => c.name));
 15→
 16→export const handleGetIndex = async (): Promise<Response> => {
 17→  const [markers, circles] = await Promise.all([getMarkers(), getCircles()]);
 18→  const html = renderPage(markers, circles);
 19→  return new Response(html, {
 20→    headers: { 'Content-Type': 'text/html; charset=utf-8' },
 21→  });
 22→};
 23→
 24→export const handleGetMarkers = async (url: URL): Promise<Response> => {
 25→  const markers = await getMarkers();
 26→  const category = url.searchParams.get('category');
 27→  const filtered = category
 28→    ? markers.filter((m) => m.category === category)
 29→    : markers;
 30→  return jsonResponse(filtered);
 31→};
 32→
 33→export const handlePostMarker = async (req: Request): Promise<Response> => {
 34→  const body = await req.json() as Record<string, unknown>;
 35→  const { lat, lng, title, description, category } = body;
 36→
 37→  if (typeof lat !== 'number' || typeof lng !== 'number' || typeof title !== 'string' || !title.trim()) {
 38→    return jsonResponse({ error: 'lat (number), lng (number), and title (string) are required' }, 400);
 39→  }
 40→
 41→  const cat = (typeof category === 'string' && validCategories.has(category))
 42→    ? category as MarkerCategory
 43→    : 'general';
 44→
 45→  const marker: MapMarker = {
 46→    id: generateId(),
 47→    lat,
 48→    lng,
 49→    title: title.trim(),
 50→    description: typeof description === 'string' ? description.trim() : '',
 51→    category: cat,
 52→    createdAt: new Date().toISOString(),
 53→  };
 54→
 55→  const saved = await addMarker(marker);
 56→  return jsonResponse(saved, 201);
 57→};
 58→
 59→export const handleDeleteMarker = async (id: string): Promise<Response> => {
 60→  const deleted = await deleteMarker(id);
 61→  if (!deleted) return jsonResponse({ error: 'Marker not found' }, 404);
 62→  return jsonResponse({ ok: true });
 63→};
 64→
 65→export const handleGetCircles = async (): Promise<Response> => {
 66→  const circles = await getCircles();
 67→  return jsonResponse(circles);
 68→};
