 70→export const handlePostCircle = async (req: Request): Promise<Response> => {
 71→  const body = await req.json() as Record<string, unknown>;
 72→  const { lat, lng, radius, color, label } = body;
 73→
 74→  if (typeof lat !== 'number' || typeof lng !== 'number' || typeof radius !== 'number' || radius < 50) {
 75→    return jsonResponse({ error: 'lat (number), lng (number), and radius (number >= 50) are required' }, 400);
 76→  }
 77→
 78→  const circle: MapCircle = {
 79→    id: generateId(),
 80→    lat,
 81→    lng,
 82→    radius,
 83→    color: typeof color === 'string' ? color : '#2196F3',
 84→    label: typeof label === 'string' ? label.trim() : '',
 85→    createdAt: new Date().toISOString(),
 86→  };
 87→
 88→  const saved = await addCircle(circle);
 89→  return jsonResponse(saved, 201);
 90→};
 91→
 92→export const handleDeleteCircle = async (id: string): Promise<Response> => {
 93→  const deleted = await deleteCircle(id);
 94→  if (!deleted) return jsonResponse({ error: 'Circle not found' }, 404);
 95→  return jsonResponse({ ok: true });
 96→};
