 98→export const handleSearch = async (url: URL): Promise<Response> => {
 99→  const q = url.searchParams.get('q');
100→  if (!q) return jsonResponse({ error: 'q parameter required' }, 400);
101→
102→  const nominatimUrl = `https://nominatim.openstreetmap.org/search?format=json&limit=5&q=${encodeURIComponent(q)}`;
103→  const res = await fetch(nominatimUrl, {
104→    headers: { 'User-Agent': 'interactive-map-module/1.0' },
105→  });
106→  const results = (await res.json()) as NominatimResult[];
