import type { CalendarEvent, EventInput } from './types'

const DATA_PATH = `${import.meta.dir}/data/events.json`

const generateId = (): string =>
  `evt_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`

const readEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return JSON.parse(text) as CalendarEvent[]
}

const writeEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2))
}

export const getAllEvents = async (): Promise<CalendarEvent[]> => readEvents()

export const getEventById = async (id: string): Promise<CalendarEvent | undefined> => {
  const events = await readEvents()
  return events.find((e) => e.id === id)
}

export const createEvent = async (input: EventInput): Promise<CalendarEvent> => {
  const events = await readEvents()
  const event: CalendarEvent = {
    ...input,
    id: input.id ?? generateId(),
    description: input.description ?? '',
    recurrence: input.recurrence ?? 'none',
  }
  events.push(event)
  await writeEvents(events)
  return event
}

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | undefined> => {
  const events = await readEvents()
  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return undefined
  events[idx] = { ...events[idx], ...updates }
  await writeEvents(events)
  return events[idx]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readEvents()
  const filtered = events.filter((e) => e.id !== id)
  if (filtered.length === events.length) return false
  await writeEvents(filtered)
  return true
}

import type { CalendarEvent } from './types'

const parseDate = (dateStr: string): Date => {
  const [y, m, d] = dateStr.split('-').map(Number)
  return new Date(y, m - 1, d)
}

const formatDate = (date: Date): string => {
  const y = date.getFullYear()
  const m = String(date.getMonth() + 1).padStart(2, '0')
  const d = String(date.getDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}

const addDays = (date: Date, days: number): Date => {
  const result = new Date(date)
  result.setDate(result.getDate() + days)
  return result
}

const addMonths = (date: Date, months: number): Date => {
  const result = new Date(date)
  result.setMonth(result.getMonth() + months)
  return result
}

/** Expand recurring events into concrete occurrences within a date range */
export const expandRecurrences = (
  events: CalendarEvent[],
  rangeStart: string,
  rangeEnd: string
): CalendarEvent[] => {
  const start = parseDate(rangeStart)
  const end = parseDate(rangeEnd)
  const results: CalendarEvent[] = []

  for (const event of events) {
    if (event.recurrence === 'none') {
      const eventDate = parseDate(event.date)
      if (eventDate >= start && eventDate <= end) {
        results.push(event)
      }
      continue
    }

    const origin = parseDate(event.date)
    let current = new Date(origin)

    // Cap expansion to prevent runaway loops
    const maxIterations = 400
    let iterations = 0

    while (current <= end && iterations < maxIterations) {
      if (current >= start) {
        results.push({
          ...event,
          date: formatDate(current),
        })
      }

      iterations++
      switch (event.recurrence) {
        case 'daily':
          current = addDays(current, 1)
          break
        case 'weekly':
          current = addDays(current, 7)
          break
        case 'monthly':
          current = addMonths(origin, iterations)
          break
      }
    }
  }

  return results
}

/** Get all event occurrences for a single date */
export const getOccurrencesForDate = (
  events: CalendarEvent[],
  date: string
): CalendarEvent[] =>
  expandRecurrences(events, date, date).sort((a, b) =>
    a.startTime.localeCompare(b.startTime)
  )

/** Get all event occurrences for a month (year is full year, month is 0-indexed) */
export const getOccurrencesForMonth = (
  events: CalendarEvent[],
  year: number,
  month: number
): CalendarEvent[] => {
  const firstDay = new Date(year, month, 1)
  const lastDay = new Date(year, month + 1, 0)
  return expandRecurrences(events, formatDate(firstDay), formatDate(lastDay))
}

import type { CalendarEvent, DayCell, MonthGrid } from './types'
import { MONTH_NAMES } from './types'

const formatDate = (date: Date): string => {
  const y = date.getFullYear()
  const m = String(date.getMonth() + 1).padStart(2, '0')
  const d = String(date.getDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}

const todayStr = (): string => formatDate(new Date())

/** Build a month grid with 6 weeks of day cells, annotated with events */
export const buildMonthGrid = (
  year: number,
  month: number,
  eventsByDate: Map<string, CalendarEvent[]>
): MonthGrid => {
  const firstOfMonth = new Date(year, month, 1)
  const startDay = firstOfMonth.getDay() // 0=Sun
  const today = todayStr()

  // Start from the Sunday of the week containing the 1st
  const gridStart = new Date(year, month, 1 - startDay)

  const weeks: DayCell[][] = []

  for (let w = 0; w < 6; w++) {
    const week: DayCell[] = []
    for (let d = 0; d < 7; d++) {
      const cellDate = new Date(gridStart)
      cellDate.setDate(gridStart.getDate() + w * 7 + d)
      const dateStr = formatDate(cellDate)

      week.push({
        date: dateStr,
        day: cellDate.getDate(),
        isCurrentMonth: cellDate.getMonth() === month,
        isToday: dateStr === today,
        events: eventsByDate.get(dateStr) ?? [],
      })
    }
    weeks.push(week)
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  }
}

