import { buildMonthGrid } from './calendar'
import { getOccurrencesForDate, getOccurrencesForMonth } from './recurrence'
import {
  getAllEvents,
  getEventById,
  createEvent,
  updateEvent,
  deleteEvent,
} from './store'
import { MonthView, DayView, EventForm } from './views'
import type { CalendarEvent, EventInput, MonthGrid } from './types'

export type { CalendarEvent, EventInput, MonthGrid }

/** Get the full month grid with events populated */
export const getMonthGrid = async (year: number, month: number): Promise<MonthGrid> => {
  const events = await getAllEvents()
  const occurrences = getOccurrencesForMonth(events, year, month)

  const byDate = new Map<string, CalendarEvent[]>()
  for (const evt of occurrences) {
    const list = byDate.get(evt.date) ?? []
    list.push(evt)
    byDate.set(evt.date, list)
  }

  return buildMonthGrid(year, month, byDate)
}

/** Get all events for a specific date, sorted by start time */
export const getEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await getAllEvents()
  return getOccurrencesForDate(events, date)
}

/** Render the month view as HTML */
export const renderMonthView = async (year: number, month: number): Promise<ReturnType<typeof MonthView>> => {
  const grid = await getMonthGrid(year, month)
  return MonthView({ grid })
}

/** Render the day view as HTML */
export const renderDayView = async (date: string): Promise<ReturnType<typeof DayView>> => {
  const events = await getEventsForDate(date)
  return DayView({ date, events })
}

/** Render the event creation form */
export const renderNewEventForm = (defaultDate?: string) =>
  EventForm({ defaultDate })

/** Render the event edit form */
export const renderEditEventForm = async (eventId: string) => {
  const event = await getEventById(eventId)
  if (!event) return null
  return EventForm({ event })
}

export {
  createEvent,
  updateEvent,
  deleteEvent,
  getEventById,
  getAllEvents,
}

