18→export const buildMonthGrid = (
19→  year: number,
20→  month: number,
21→  events: CalendarEvent[],
22→): MonthGrid => {
23→  const firstDay = new Date(year, month, 1);
24→  const lastDay = new Date(year, month + 1, 0);
25→  const startDow = firstDay.getDay(); // 0=Sunday
26→
27→  // Expand range to include padding days
28→  const gridStart = new Date(firstDay);
29→  gridStart.setDate(gridStart.getDate() - startDow);
30→
31→  const daysInGrid = Math.ceil((startDow + lastDay.getDate()) / 7) * 7;
32→  const gridEnd = new Date(gridStart);
33→  gridEnd.setDate(gridEnd.getDate() + daysInGrid - 1);
34→
35→  const rangeStart = formatDate(gridStart);
36→  const rangeEnd = formatDate(gridEnd);
37→  const expanded = expandRecurrences(events, rangeStart, rangeEnd);
38→
39→  const eventsByDate = new Map<string, CalendarEvent[]>();
40→  for (const evt of expanded) {
41→    const list = eventsByDate.get(evt.date) ?? [];
42→    list.push(evt);
43→    eventsByDate.set(evt.date, list);
44→  }
45→
46→  const today = todayStr();
47→  const weeks: CalendarDay[][] = [];
48→  let currentDate = new Date(gridStart);
49→
50→  for (let i = 0; i < daysInGrid; i++) {
51→    const weekIdx = Math.floor(i / 7);
52→    if (!weeks[weekIdx]) weeks[weekIdx] = [];
53→
54→    const dateStr = formatDate(currentDate);
55→    const dayEvents = eventsByDate.get(dateStr) ?? [];
56→    dayEvents.sort((a, b) => a.startTime.localeCompare(b.startTime));
57→
58→    weeks[weekIdx].push({
59→      date: dateStr,
60→      dayOfMonth: currentDate.getDate(),
61→      isCurrentMonth: currentDate.getMonth() === month,
62→      isToday: dateStr === today,
63→      events: dayEvents,
64→    });
65→
66→    currentDate.setDate(currentDate.getDate() + 1);
67→  }
68→
69→  return {
70→    year,
71→    month,
72→    label: `${MONTH_NAMES[month]} ${year}`,
73→    weeks,
74→  };
75→};
