 8→const formatDate = (d: Date): string => {
 9→  const y = d.getFullYear();
10→  const m = String(d.getMonth() + 1).padStart(2, '0');
11→  const day = String(d.getDate()).padStart(2, '0');
12→  return `${y}-${m}-${day}`;
13→};
