15→const isSameOrBefore = (a: Date, b: Date): boolean =>
16→  a.getTime() <= b.getTime();
17→
18→const addDays = (d: Date, n: number): Date => {
19→  const result = new Date(d);
20→  result.setDate(result.getDate() + n);
21→  return result;
22→};
23→
24→const addWeeks = (d: Date, n: number): Date => addDays(d, n * 7);
25→
26→const addMonths = (d: Date, n: number): Date => {
27→  const result = new Date(d);
28→  result.setMonth(result.getMonth() + n);
29→  return result;
30→};
