32→export const expandRecurrences = (
33→  events: CalendarEvent[],
34→  rangeStart: string,
35→  rangeEnd: string,
36→): CalendarEvent[] => {
37→  const start = parseDate(rangeStart);
38→  const end = parseDate(rangeEnd);
39→  const expanded: CalendarEvent[] = [];
40→
41→  for (const event of events) {
42→    if (event.recurrence === 'none') {
43→      const eventDate = parseDate(event.date);
44→      if (eventDate >= start && eventDate <= end) {
45→        expanded.push(event);
46→      }
47→      continue;
48→    }
49→
50→    const originDate = parseDate(event.date);
51→    let current = new Date(originDate);
52→    let iterations = 0;
53→    const maxIterations = 366; // safety limit
54→
55→    while (isSameOrBefore(current, end) && iterations < maxIterations) {
56→      if (current >= start) {
57→        expanded.push({
58→          ...event,
59→          date: formatDate(current),
60→        });
61→      }
62→
63→      iterations++;
64→      switch (event.recurrence) {
65→        case 'daily':
66→          current = addDays(originDate, iterations);
67→          break;
68→        case 'weekly':
69→          current = addWeeks(originDate, iterations);
70→          break;
71→        case 'monthly':
72→          current = addMonths(originDate, iterations);
73→          break;
74→      }
75→    }
76→  }
77→
78→  return expanded;
79→};
