81→export const getEventsForDate = (
82→  events: CalendarEvent[],
83→  date: string,
84→): CalendarEvent[] => {
85→  const expanded = expandRecurrences(events, date, date);
86→  return expanded
87→    .filter((e) => e.date === date)
88→    .sort((a, b) => a.startTime.localeCompare(b.startTime));
89→};
