 35→const doesRecurrenceMatch = (
 36→  eventDate: string,
 37→  targetDate: string,
 38→  recurrence: RecurrenceRule
 39→): boolean => {
 40→  const event = parseDate(eventDate);
 41→  const target = parseDate(targetDate);
 42→  const eventD = new Date(event.year, event.month, event.day);
 43→  const targetD = new Date(target.year, target.month, target.day);
 44→
 45→  if (targetD < eventD) return false;
 46→
 47→  switch (recurrence) {
 48→    case 'daily':
 49→      return true;
 50→    case 'weekly': {
 51→      return eventD.getDay() === targetD.getDay();
 52→    }
 53→    case 'monthly': {
 54→      return event.day === target.day;
 55→    }
 56→  }
 57→};
