 59→export const getEventsForDate = (
 60→  events: CalendarEvent[],
 61→  dateStr: string,
 62→  categoryFilter: EventCategory | null = null
 63→): CalendarEvent[] => {
 64→  const matching = events.filter((event) => {
 65→    if (categoryFilter && event.category !== categoryFilter) return false;
 66→    if (event.date === dateStr) return true;
 67→    if (event.recurrence && doesRecurrenceMatch(event.date, dateStr, event.recurrence)) return true;
 68→    return false;
 69→  });
 70→
 71→  return matching.sort((a, b) => a.startTime.localeCompare(b.startTime));
 72→};
