 74→export const buildMonthGrid = (
 75→  year: number,
 76→  month: number,
 77→  events: CalendarEvent[],
 78→  categoryFilter: EventCategory | null = null
 79→): DayCell[] => {
 80→  const daysInMonth = getDaysInMonth(year, month);
 81→  const firstDay = getFirstDayOfWeek(year, month);
 82→  const today = getTodayString();
 83→  const cells: DayCell[] = [];
 84→
 85→  // Previous month padding
 86→  const prevMonth = month === 0 ? 11 : month - 1;
 87→  const prevYear = month === 0 ? year - 1 : year;
 88→  const daysInPrev = getDaysInMonth(prevYear, prevMonth);
 89→
 90→  for (let i = firstDay - 1; i >= 0; i--) {
 91→    const day = daysInPrev - i;
 92→    const date = formatDate(prevYear, prevMonth, day);
 93→    const dayEvents = getEventsForDate(events, date, categoryFilter);
 94→    cells.push({
 95→      date,
 96→      day,
 97→      inMonth: false,
 98→      isToday: date === today,
 99→      hasEvents: dayEvents.length > 0,
100→      eventCategories: [...new Set(dayEvents.map((e) => e.category))],
101→    });
102→  }
103→
104→  // Current month
105→  for (let day = 1; day <= daysInMonth; day++) {
106→    const date = formatDate(year, month, day);
107→    const dayEvents = getEventsForDate(events, date, categoryFilter);
108→    cells.push({
109→      date,
110→      day,
111→      inMonth: true,
112→      isToday: date === today,
113→      hasEvents: dayEvents.length > 0,
114→      eventCategories: [...new Set(dayEvents.map((e) => e.category))],
115→    });
116→  }
117→
118→  // Next month padding
119→  const nextMonth = month === 11 ? 0 : month + 1;
120→  const nextYear = month === 11 ? year + 1 : year;
121→  const remaining = 42 - cells.length;
122→
123→  for (let day = 1; day <= remaining; day++) {
124→    const date = formatDate(nextYear, nextMonth, day);
125→    const dayEvents = getEventsForDate(events, date, categoryFilter);
126→    cells.push({
127→      date,
128→      day,
129→      inMonth: false,
130→      isToday: date === today,
131→      hasEvents: dayEvents.length > 0,
132→      eventCategories: [...new Set(dayEvents.map((e) => e.category))],
133→    });
134→  }
135→
136→  return cells;
137→};
