139→export const navigateMonth = (
140→  year: number,
141→  month: number,
142→  direction: -1 | 1
143→): { year: number; month: number } => {
144→  let newMonth = month + direction;
145→  let newYear = year;
146→  if (newMonth < 0) {
147→    newMonth = 11;
148→    newYear--;
149→  } else if (newMonth > 11) {
150→    newMonth = 0;
151→    newYear++;
152→  }
153→  return { year: newYear, month: newMonth };
154→};
