157→  const [h, m] = time.split(':').map(Number);
158→  const period = h >= 12 ? 'PM' : 'AM';
159→  const hour12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
160→  return `${hour12}:${String(m).padStart(2, '0')} ${period}`;
