163→export const formatDateDisplay = (dateStr: string): string => {
164→  const { year, month, day } = parseDate(dateStr);
165→  const d = new Date(year, month, day);
166→  const dayName = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][d.getDay()];
167→  return `${dayName}, ${getMonthName(month)} ${day}, ${year}`;
168→};
