 40→export const handleAction = async (
 41→  action: string,
 42→  payload: string = '',
 43→  formData: Record<string, string> = {}
 44→): Promise<{ html: string; state: CalendarState }> => {
 45→  switch (action) {
 46→    case 'navigateMonth': {
 47→      const direction = Number(payload) as -1 | 1;
 48→      const nav = navigateMonth(state.year, state.month, direction);
 49→      state = { ...state, year: nav.year, month: nav.month };
 50→      break;
 51→    }
 52→
 53→    case 'selectDate': {
 54→      state = { ...state, view: 'day', selectedDate: payload };
 55→      break;
 56→    }
 57→
 58→    case 'backToMonth': {
 59→      state = { ...state, view: 'month', selectedDate: null };
 60→      break;
 61→    }
 62→
 63→    case 'filterCategory': {
 64→      const filter = payload === 'all' ? null : (payload as EventCategory);
 65→      state = { ...state, categoryFilter: filter };
 66→      break;
 67→    }
 68→
 69→    case 'showEventForm': {
 70→      const html = await renderForm(payload);
 71→      return { html, state };
 72→    }
 73→
 74→    case 'editEvent': {
 75→      const event = await getEventById(payload);
 76→      if (event) {
 77→        const html = await renderForm(event.date, event.id);
 78→        return { html, state };
 79→      }
 80→      break;
 81→    }
 82→
 83→    case 'createEvent': {
 84→      const recurrence =
 85→        formData.recurrence === 'none' ? null : (formData.recurrence as RecurrenceRule);
 86→      await addEvent({
 87→        title: formData.title,
 88→        date: formData.date,
 89→        startTime: formData.startTime,
 90→        endTime: formData.endTime,
 91→        description: formData.description ?? '',
 92→        category: (formData.category as EventCategory) ?? 'personal',
 93→        recurrence,
 94→      });
 95→      break;
 96→    }
 97→
 98→    case 'updateEvent': {
 99→      const eventId = formData.eventId;
100→      if (eventId) {
101→        const recurrence =
102→          formData.recurrence === 'none' ? null : (formData.recurrence as RecurrenceRule);
103→        await updateEvent(eventId, {
