 44→  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
 45→});
 46→
 47→const reorderLayers = (state: CanvasState, fromIndex: number, toIndex: number): CanvasState => {
 48→  const layers = [...state.layers];
 49→  const [moved] = layers.splice(fromIndex, 1);
 50→  layers.splice(toIndex, 0, moved);
 51→  return { ...state, layers };
 52→};
 53→
 54→const addActionToLayer = (state: CanvasState, layerId: string, action: DrawAction): CanvasState => ({
 55→  ...state,
 56→  layers: state.layers.map((l) =>
 57→    l.id === layerId ? { ...l, actions: [...l.actions, action] } : l
 58→  ),
 59→});
 60→
 61→const removeLastActionFromLayer = (state: CanvasState, layerId: string): { state: CanvasState; removed: DrawAction | undefined } => {
 62→  const layer = state.layers.find((l) => l.id === layerId);
 63→  if (!layer || layer.actions.length === 0) return { state, removed: undefined };
 64→  const removed = layer.actions[layer.actions.length - 1];
 65→  return {
 66→    state: {
 67→      ...state,
 68→      layers: state.layers.map((l) =>
 69→        l.id === layerId ? { ...l, actions: l.actions.slice(0, -1) } : l
 70→      ),
 71→    },
 72→    removed,
 73→  };
 74→};
 75→
 76→const clearLayer = (state: CanvasState, layerId: string): CanvasState => ({
 77→  ...state,
 78→  layers: state.layers.map((l) => (l.id === layerId ? { ...l, actions: [] } : l)),
 79→});
 80→
 81→const clearAllLayers = (state: CanvasState): CanvasState => ({
 82→  ...state,
 83→  layers: state.layers.map((l) => ({ ...l, actions: [] })),
 84→});
 85→
 86→export type CanvasEngine = {
 87→  getState: () => CanvasState;
 88→  getActiveLayer: () => Layer | undefined;
 89→  setActiveTool: (tool: Tool) => void;
 90→  getActiveTool: () => Tool;
 91→  setColor: (color: string) => void;
 92→  getColor: () => string;
 93→  setBrushSize: (size: number) => void;
 94→  getBrushSize: () => number;
 95→  addLayer: (name?: string) => void;
 96→  removeLayer: (layerId: string) => void;
 97→  setActiveLayer: (layerId: string) => void;
 98→  toggleLayerVisibility: (layerId: string) => void;
 99→  reorderLayers: (fromIndex: number, toIndex: number) => void;
100→  startStroke: (point: Point) => void;
101→  continueStroke: (point: Point) => void;
102→  endStroke: (point: Point) => void;
103→  undo: () => void;
104→  redo: () => void;
105→  canUndo: () => boolean;
106→  canRedo: () => boolean;
107→  clearActiveLayer: () => void;
108→  clearAll: () => void;
109→  toJSON: () => string;
110→  fromJSON: (json: string) => void;
111→};
112→
113→const createCanvasEngine = (width = 800, height = 600): CanvasEngine => {
114→  let state = createInitialState(width, height);
115→  let activeTool: Tool = 'pen';
116→  let color = '#000000';
117→  let brushSize = 4;
118→  let currentStrokePoints: Point[] = [];
119→  let undoStack: HistoryEntry[] = [];
120→  let redoStack: HistoryEntry[] = [];
121→
122→  const engine: CanvasEngine = {
123→    getState: () => state,
124→    getActiveLayer: () => getActiveLayer(state),
125→
126→    setActiveTool: (tool) => {
127→      activeTool = tool;
128→    },
129→    getActiveTool: () => activeTool,
130→
131→    setColor: (c) => {
132→      color = c;
133→    },
134→    getColor: () => color,
135→
136→    setBrushSize: (size) => {
137→      brushSize = Math.max(1, Math.min(100, size));
138→    },
139→    getBrushSize: () => brushSize,
140→
141→    addLayer: (name) => {
142→      state = addLayer(state, name);
143→    },
144→    removeLayer: (layerId) => {
145→      state = removeLayer(state, layerId);
146→    },
147→    setActiveLayer: (layerId) => {
148→      state = { ...state, activeLayerId: layerId };
149→    },
150→    toggleLayerVisibility: (layerId) => {
151→      state = toggleLayerVisibility(state, layerId);
152→    },
153→    reorderLayers: (fromIndex, toIndex) => {
154→      state = reorderLayers(state, fromIndex, toIndex);
155→    },
156→
157→    startStroke: (point) => {
158→      currentStrokePoints = [point];
159→    },
160→    continueStroke: (point) => {
161→      currentStrokePoints.push(point);
162→    },
163→    endStroke: (point) => {
164→      const active = getActiveLayer(state);
165→      if (!active) return;
166→
167→      let action: DrawAction;
168→      if (activeTool === 'pen' || activeTool === 'eraser') {
169→        currentStrokePoints.push(point);
170→        action = {
171→          type: activeTool,
172→          points: [...currentStrokePoints],
173→          color: activeTool === 'eraser' ? '#ffffff' : color,
174→          size: brushSize,
175→        };
176→      } else {
177→        const start = currentStrokePoints[0] ?? point;
178→        action = {
179→          type: activeTool,
180→          start,
181→          end: point,
182→          color,
183→          size: brushSize,
184→        };
185→      }
186→
187→      state = addActionToLayer(state, active.id, action);
188→      undoStack.push({ layerId: active.id, action });
189→      redoStack = [];
190→      currentStrokePoints = [];
191→    },
192→
193→    undo: () => {
194→      const entry = undoStack.pop();
195→      if (!entry) return;
196→      const result = removeLastActionFromLayer(state, entry.layerId);
197→      state = result.state;
198→      if (result.removed) {
199→        redoStack.push(entry);
200→      }
201→    },
202→    redo: () => {
203→      const entry = redoStack.pop();
204→      if (!entry) return;
205→      state = addActionToLayer(state, entry.layerId, entry.action);
206→      undoStack.push(entry);
207→    },
208→    canUndo: () => undoStack.length > 0,
209→    canRedo: () => redoStack.length > 0,
210→
211→    clearActiveLayer: () => {
212→      const active = getActiveLayer(state);
213→      if (!active) return;
214→      state = clearLayer(state, active.id);
215→      undoStack = undoStack.filter((e) => e.layerId !== active.id);
216→      redoStack = redoStack.filter((e) => e.layerId !== active.id);
217→    },
218→    clearAll: () => {
219→      state = clearAllLayers(state);
220→      undoStack = [];
221→      redoStack = [];
222→    },
223→
224→    toJSON: () => JSON.stringify(state, null, 2),
225→    fromJSON: (json) => {
226→      const parsed = JSON.parse(json) as CanvasState;
227→      state = parsed;
228→      undoStack = [];
229→      redoStack = [];
230→    },
231→  };
232→
233→  return engine;
234→};
235→
236→export { createCanvasEngine, createLayer, createInitialState };
