  1→import type { CanvasState, DrawAction, Layer, StrokeSegment, ShapeAction } from './types';
  2→
  3→const isStroke = (action: DrawAction): action is StrokeSegment =>
  4→  action.type === 'pen' || action.type === 'eraser';
  5→
  6→const isShape = (action: DrawAction): action is ShapeAction =>
  7→  action.type === 'rectangle' || action.type === 'circle' || action.type === 'line';
  8→
  9→const renderStroke = (ctx: CanvasRenderingContext2D, stroke: StrokeSegment): void => {
 10→  if (stroke.points.length < 2) return;
 11→
 12→  ctx.save();
 13→  ctx.strokeStyle = stroke.color;
 14→  ctx.lineWidth = stroke.size;
 15→  ctx.lineCap = 'round';
 16→  ctx.lineJoin = 'round';
 17→
 18→  if (stroke.type === 'eraser') {
 19→    ctx.globalCompositeOperation = 'destination-out';
 20→  }
 21→
 22→  ctx.beginPath();
 23→  ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
 24→  for (let i = 1; i < stroke.points.length; i++) {
 25→    ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
 26→  }
 27→  ctx.stroke();
 28→  ctx.restore();
 29→};
 30→
 31→const renderShape = (ctx: CanvasRenderingContext2D, shape: ShapeAction): void => {
 32→  ctx.save();
 33→  ctx.strokeStyle = shape.color;
 34→  ctx.lineWidth = shape.size;
 35→  ctx.lineCap = 'round';
 36→
 37→  switch (shape.type) {
 38→    case 'rectangle': {
 39→      const x = Math.min(shape.start.x, shape.end.x);
 40→      const y = Math.min(shape.start.y, shape.end.y);
 41→      const w = Math.abs(shape.end.x - shape.start.x);
 42→      const h = Math.abs(shape.end.y - shape.start.y);
 43→      ctx.strokeRect(x, y, w, h);
 44→      break;
 45→    }
 46→    case 'circle': {
 47→      const cx = (shape.start.x + shape.end.x) / 2;
 48→      const cy = (shape.start.y + shape.end.y) / 2;
 49→      const rx = Math.abs(shape.end.x - shape.start.x) / 2;
 50→      const ry = Math.abs(shape.end.y - shape.start.y) / 2;
 51→      ctx.beginPath();
 52→      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
 53→      ctx.stroke();
 54→      break;
 55→    }
 56→    case 'line': {
 57→      ctx.beginPath();
 58→      ctx.moveTo(shape.start.x, shape.start.y);
 59→      ctx.lineTo(shape.end.x, shape.end.y);
 60→      ctx.stroke();
 61→      break;
 62→    }
 63→  }
 64→
 65→  ctx.restore();
 66→};
 67→
 68→const renderAction = (ctx: CanvasRenderingContext2D, action: DrawAction): void => {
 69→  if (isStroke(action)) {
 70→    renderStroke(ctx, action);
 71→  } else if (isShape(action)) {
 72→    renderShape(ctx, action);
 73→  }
 74→};
 75→
 76→const renderLayer = (ctx: CanvasRenderingContext2D, layer: Layer): void => {
 77→  if (!layer.visible) return;
 78→  for (const action of layer.actions) {
 79→    renderAction(ctx, action);
 80→  }
 81→};
 82→
 83→const renderCanvas = (ctx: CanvasRenderingContext2D, state: CanvasState): void => {
 84→  ctx.clearRect(0, 0, state.width, state.height);
 85→
 86→  // White background
 87→  ctx.fillStyle = '#ffffff';
 88→  ctx.fillRect(0, 0, state.width, state.height);
 89→
 90→  for (const layer of state.layers) {
 91→    renderLayer(ctx, layer);
 92→  }
 93→};
 94→
 95→const renderLayerThumbnail = (
 96→  ctx: CanvasRenderingContext2D,
 97→  layer: Layer,
 98→  thumbWidth: number,
 99→  thumbHeight: number,
100→  canvasWidth: number,
101→  canvasHeight: number
102→): void => {
103→  ctx.clearRect(0, 0, thumbWidth, thumbHeight);
104→
105→  // Checkerboard background to indicate transparency
106→  const checkSize = 4;
107→  for (let y = 0; y < thumbHeight; y += checkSize) {
108→    for (let x = 0; x < thumbWidth; x += checkSize) {
109→      const isLight = ((x / checkSize) + (y / checkSize)) % 2 === 0;
110→      ctx.fillStyle = isLight ? '#e0e0e0' : '#c0c0c0';
111→      ctx.fillRect(x, y, checkSize, checkSize);
112→    }
113→  }
114→
115→  // Scale to fit
116→  const scaleX = thumbWidth / canvasWidth;
117→  const scaleY = thumbHeight / canvasHeight;
118→  ctx.save();
119→  ctx.scale(scaleX, scaleY);
120→
121→  for (const action of layer.actions) {
122→    renderAction(ctx, action);
123→  }
124→
125→  ctx.restore();
126→
127→  // Dim if not visible
128→  if (!layer.visible) {
129→    ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
130→    ctx.fillRect(0, 0, thumbWidth, thumbHeight);
131→  }
132→};
133→
134→export { renderCanvas, renderLayer, renderLayerThumbnail, renderAction };
