  1→import type { CanvasState, DrawingMetadata } from './types';
  2→
  3→const DATA_DIR = './data';
  4→const DRAWINGS_INDEX = `${DATA_DIR}/drawings.json`;
  5→
  6→const ensureDataDir = async (): Promise<void> => {
  7→  const dir = Bun.file(DATA_DIR);
  8→  try {
  9→    await Bun.write(`${DATA_DIR}/.keep`, '');
 10→  } catch {
 11→    // directory already exists
 12→  }
 13→};
 14→
 15→const loadIndex = async (): Promise<DrawingMetadata[]> => {
 16→  const file = Bun.file(DRAWINGS_INDEX);
 17→  if (await file.exists()) {
 18→    const text = await file.text();
 19→    return JSON.parse(text) as DrawingMetadata[];
 20→  }
 21→  return [];
 22→};
 23→
 24→const saveIndex = async (entries: DrawingMetadata[]): Promise<void> => {
 25→  await Bun.write(DRAWINGS_INDEX, JSON.stringify(entries, null, 2));
 26→};
 27→
 28→const saveDrawing = async (
 29→  state: CanvasState,
 30→  name: string,
 31→  id?: string
 32→): Promise<DrawingMetadata> => {
 33→  await ensureDataDir();
 34→
 35→  const drawingId = id ?? crypto.randomUUID();
 36→  const now = new Date().toISOString();
 37→  const filePath = `${DATA_DIR}/${drawingId}.json`;
 38→
 39→  await Bun.write(filePath, JSON.stringify(state, null, 2));
 40→
 41→  const index = await loadIndex();
 42→  const existingIdx = index.findIndex((e) => e.id === drawingId);
 43→
 44→  const meta: DrawingMetadata = {
 45→    id: drawingId,
 46→    name,
 47→    createdAt: existingIdx >= 0 ? index[existingIdx].createdAt : now,
 48→    updatedAt: now,
 49→    width: state.width,
 50→    height: state.height,
 51→    layerCount: state.layers.length,
 52→  };
 53→
 54→  if (existingIdx >= 0) {
 55→    index[existingIdx] = meta;
 56→  } else {
 57→    index.push(meta);
 58→  }
 59→
 60→  await saveIndex(index);
 61→  return meta;
 62→};
 63→
 64→const loadDrawing = async (id: string): Promise<CanvasState | null> => {
 65→  const file = Bun.file(`${DATA_DIR}/${id}.json`);
 66→  if (await file.exists()) {
 67→    const text = await file.text();
 68→    return JSON.parse(text) as CanvasState;
 69→  }
 70→  return null;
 71→};
 72→
 73→const deleteDrawing = async (id: string): Promise<boolean> => {
 74→  const index = await loadIndex();
 75→  const filtered = index.filter((e) => e.id !== id);
 76→  if (filtered.length === index.length) return false;
 77→
 78→  await saveIndex(filtered);
 79→
 80→  const file = Bun.file(`${DATA_DIR}/${id}.json`);
 81→  if (await file.exists()) {
 82→    await Bun.write(`${DATA_DIR}/${id}.json`, '');
 83→  }
 84→
 85→  return true;
 86→};
 87→
 88→const listDrawings = async (): Promise<DrawingMetadata[]> => {
 89→  return loadIndex();
 90→};
 91→
 92→const savePNG = async (
 93→  pngDataUrl: string,
 94→  filename: string
 95→): Promise<string> => {
 96→  await ensureDataDir();
 97→  const base64 = pngDataUrl.replace(/^data:image\/png;base64,/, '');
 98→  const buffer = Buffer.from(base64, 'base64');
 99→  const filePath = `${DATA_DIR}/${filename}`;
100→  await Bun.write(filePath, buffer);
101→  return filePath;
102→};
103→
104→const loadPNG = async (filename: string): Promise<string | null> => {
105→  const filePath = `${DATA_DIR}/${filename}`;
106→  const file = Bun.file(filePath);
107→  if (await file.exists()) {
108→    const buffer = await file.arrayBuffer();
109→    const base64 = Buffer.from(buffer).toString('base64');
110→    return `data:image/png;base64,${base64}`;
111→  }
112→  return null;
113→};
114→
115→export { saveDrawing, loadDrawing, deleteDrawing, listDrawings, savePNG, loadPNG };
