 70→
 71→    handleToolSelect: (tool) => {
 72→      engine.setActiveTool(tool);
 73→    },
 74→
 75→    handleColorSelect: (color) => {
 76→      engine.setColor(color);
 77→    },
 78→
 79→    handleBrushSize: (size) => {
 80→      engine.setBrushSize(size);
 81→    },
 82→
 83→    handlePointerDown: (point) => {
 84→      isDrawing = true;
 85→      engine.startStroke(point);
 86→    },
 87→
 88→    handlePointerMove: (point) => {
 89→      if (!isDrawing) return;
 90→      engine.continueStroke(point);
 91→    },
 92→
 93→    handlePointerUp: (point) => {
 94→      if (!isDrawing) return;
 95→      isDrawing = false;
 96→      engine.endStroke(point);
