102→
103→    handleRedo: () => {
104→      engine.redo();
105→    },
106→
107→    handleClearLayer: () => {
108→      engine.clearActiveLayer();
109→    },
110→
111→    handleClearAll: () => {
112→      engine.clearAll();
113→    },
114→
115→    handleAddLayer: () => {
116→      engine.addLayer();
117→    },
118→
119→    handleRemoveLayer: () => {
