  5→/**
  6→ * Client-side controller that wires DOM events to the canvas engine
  7→ * and manages the render loop. Intended to run in the browser.
  8→ */
  9→const initDrawingCanvas = (rootEl: HTMLElement, canvasWidth = 800, canvasHeight = 600) => {
 10→  const engine = createCanvasEngine(canvasWidth, canvasHeight);
 11→  let isDrawing = false;
 12→  let rafId = 0;
 13→
 14→  // --- DOM refs ---
 15→  const mainCanvas = rootEl.querySelector<HTMLCanvasElement>('[p-target="main-canvas"]');
 16→  if (!mainCanvas) throw new Error('main-canvas not found');
 17→  const ctx = mainCanvas.getContext('2d')!;
 18→
 19→  // --- helpers ---
 20→  const canvasPoint = (e: PointerEvent): Point => {
 21→    const rect = mainCanvas.getBoundingClientRect();
 22→    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
 23→  };
 24→
 25→  const scheduleRender = () => {
 26→    cancelAnimationFrame(rafId);
 27→    rafId = requestAnimationFrame(() => {
 28→      renderCanvas(ctx, engine.getState());
 29→      updateThumbnails();
 30→      updateUI();
 31→    });
 32→  };
 33→
 34→  const updateThumbnails = () => {
 35→    const state = engine.getState();
 36→    for (const layer of state.layers) {
 37→      const thumbCanvas = rootEl.querySelector<HTMLCanvasElement>(
 38→        `[p-target="layer-thumb-${layer.id}"]`
 39→      );
 40→      if (!thumbCanvas) continue;
 41→      const thumbCtx = thumbCanvas.getContext('2d');
 42→      if (!thumbCtx) continue;
 43→      renderLayerThumbnail(thumbCtx, layer, 40, 30, state.width, state.height);
 44→    }
 45→  };
 46→
 47→  const updateUI = () => {
 48→    // Update tool buttons
 49→    rootEl.querySelectorAll<HTMLButtonElement>('[p-trigger^="tool-select:"]').forEach((btn) => {
 50→      const tool = btn.getAttribute('p-trigger')?.split(':')[1];
 51→      const isActive = tool === engine.getActiveTool();
 52→      btn.style.backgroundColor = isActive ? '#094771' : '#3c3c3c';
 53→      btn.style.borderColor = isActive ? '#1177bb' : '#555';
 54→    });
 55→
 56→    // Update undo/redo
 57→    const undoBtn = rootEl.querySelector<HTMLButtonElement>('[p-trigger="undo"]');
 58→    const redoBtn = rootEl.querySelector<HTMLButtonElement>('[p-trigger="redo"]');
 59→    if (undoBtn) undoBtn.style.opacity = engine.canUndo() ? '1' : '0.4';
 60→    if (redoBtn) redoBtn.style.opacity = engine.canRedo() ? '1' : '0.4';
 61→
 62→    // Update color swatches
 63→    rootEl.querySelectorAll<HTMLElement>('[p-trigger^="color-select:"]').forEach((swatch) => {
 64→      const color = swatch.getAttribute('p-trigger')?.split(':')[1];
 65→      swatch.style.borderColor = color === engine.getColor() ? '#1177bb' : 'transparent';
 66→    });
 67→
 68→    // Update layer highlights
 69→    const state = engine.getState();
 70→    rootEl.querySelectorAll<HTMLElement>('[p-trigger^="layer-select:"]').forEach((item) => {
 71→      const layerId = item.getAttribute('p-trigger')?.split(':')[1];
 72→      item.style.backgroundColor = layerId === state.activeLayerId ? '#094771' : 'transparent';
 73→    });
 74→  };
 75→
 76→  // --- pointer events on canvas ---
 77→  mainCanvas.addEventListener('pointerdown', (e) => {
 78→    isDrawing = true;
 79→    mainCanvas.setPointerCapture(e.pointerId);
 80→    engine.startStroke(canvasPoint(e));
 81→  });
 82→
 83→  mainCanvas.addEventListener('pointermove', (e) => {
 84→    if (!isDrawing) return;
 85→    engine.continueStroke(canvasPoint(e));
 86→    // Live preview for pen/eraser
 87→    const tool = engine.getActiveTool();
 88→    if (tool === 'pen' || tool === 'eraser') {
 89→      renderCanvas(ctx, engine.getState());
 90→      // Draw current stroke in progress
 91→      const state = engine.getState();
 92→      // handled by next frame
 93→    }
 94→    scheduleRender();
 95→  });
 96→
 97→  mainCanvas.addEventListener('pointerup', (e) => {
 98→    if (!isDrawing) return;
 99→    isDrawing = false;
100→    engine.endStroke(canvasPoint(e));
101→    scheduleRender();
102→  });
103→
104→  // --- delegated click handler for toolbar/sidebar ---
105→  rootEl.addEventListener('click', (e) => {
106→    const target = (e.target as HTMLElement).closest<HTMLElement>('[p-trigger]');
107→    if (!target) return;
108→    const trigger = target.getAttribute('p-trigger') ?? '';
109→    const [action, value] = trigger.split(':');
110→
111→    switch (action) {
112→      case 'tool-select':
113→        engine.setActiveTool(value as Tool);
114→        break;
115→      case 'color-select':
116→        engine.setColor(value);
117→        break;
118→      case 'undo':
119→        engine.undo();
120→        break;
121→      case 'redo':
122→        engine.redo();
123→        break;
124→      case 'clear-layer':
125→        engine.clearActiveLayer();
126→        break;
127→      case 'clear-all':
128→        engine.clearAll();
129→        break;
130→      case 'add-layer':
131→        engine.addLayer();
132→        break;
133→      case 'remove-layer': {
134→        const active = engine.getActiveLayer();
135→        if (active) engine.removeLayer(active.id);
136→        break;
137→      }
138→      case 'layer-select':
139→        engine.setActiveLayer(value);
140→        break;
141→      case 'toggle-visibility':
142→        engine.toggleLayerVisibility(value);
143→        break;
144→      case 'save-png': {
145→        const dataUrl = mainCanvas.toDataURL('image/png');
146→        const link = document.createElement('a');
147→        link.download = 'drawing.png';
148→        link.href = dataUrl;
149→        link.click();
150→        return; // no re-render needed
151→      }
152→      case 'load-png': {
153→        const input = document.createElement('input');
154→        input.type = 'file';
155→        input.accept = 'image/png';
156→        input.onchange = () => {
157→          const file = input.files?.[0];
158→          if (!file) return;
159→          const img = new Image();
160→          img.onload = () => {
161→            const activeLayer = engine.getActiveLayer();
162→            if (!activeLayer) return;
163→            ctx.drawImage(img, 0, 0);
164→          };
165→          img.src = URL.createObjectURL(file);
166→        };
167→        input.click();
168→        return;
169→      }
170→      case 'save-project': {
171→        const json = engine.toJSON();
172→        const blob = new Blob([json], { type: 'application/json' });
173→        const link = document.createElement('a');
174→        link.download = 'drawing.json';
175→        link.href = URL.createObjectURL(blob);
176→        link.click();
177→        return;
178→      }
179→      case 'load-project': {
180→        const input = document.createElement('input');
181→        input.type = 'file';
182→        input.accept = 'application/json';
183→        input.onchange = async () => {
184→          const file = input.files?.[0];
185→          if (!file) return;
186→          const text = await file.text();
187→          engine.fromJSON(text);
188→          scheduleRender();
189→        };
190→        input.click();
191→        return;
192→      }
193→      default:
194→        return;
195→    }
196→
197→    scheduleRender();
198→  });
199→
200→  // --- input events for range/color ---
201→  rootEl.addEventListener('input', (e) => {
202→    const target = e.target as HTMLInputElement;
203→    const trigger = target.getAttribute('p-trigger');
204→    if (trigger === 'brush-size') {
205→      engine.setBrushSize(Number(target.value));
206→      const preview = rootEl.querySelector<HTMLElement>('[p-trigger="brush-size"]')
207→        ?.parentElement?.querySelector<HTMLElement>('div > div');
208→      if (preview) {
209→        const s = Math.min(Number(target.value), 50);
210→        preview.style.width = `${s}px`;
211→        preview.style.height = `${s}px`;
212→      }
213→    } else if (trigger === 'color-input') {
214→      engine.setColor(target.value);
215→      scheduleRender();
216→    }
217→  });
218→
219→  // --- keyboard shortcuts ---
220→  document.addEventListener('keydown', (e) => {
221→    if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
222→      e.preventDefault();
223→      if (e.shiftKey) {
224→        engine.redo();
225→      } else {
226→        engine.undo();
227→      }
228→      scheduleRender();
229→    }
230→  });
231→
232→  // Initial render
233→  scheduleRender();
234→
235→  return { engine, scheduleRender };
236→};
