{
  "name": "@node/drawing-canvas",
  "version": "1.0.0",
  "description": "A freehand drawing canvas with shapes, layers, undo/redo, and PNG export",
  "main": "index.ts",
  "modnet": {
    "contentType": "art",
    "structure": "form",
    "mechanics": ["track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type ToolType = 'pen' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type StrokeAction = {
  kind: 'stroke'
  points: Point[]
  color: string
  size: number
  tool: 'pen' | 'eraser'
}

export type ShapeAction = {
  kind: 'shape'
  tool: 'rectangle' | 'circle' | 'line'
  start: Point
  end: Point
  color: string
  fillColor: string | null
  size: number
}

export type DrawAction = StrokeAction | ShapeAction

export type Layer = {
  id: string
  name: string
  visible: boolean
  actions: DrawAction[]
  thumbnailDataUrl: string | null
}

export type CanvasState = {
  layers: Layer[]
  activeLayerId: string
  width: number
  height: number
}

export type HistoryEntry = {
  layerId: string
  action: DrawAction
}

export type DrawingFile = {
  id: string
  name: string
  createdAt: string
  updatedAt: string
  state: CanvasState
}

export type ToolbarState = {
  activeTool: ToolType
  color: string
  fillColor: string | null
  brushSize: number
}

import type { Layer, CanvasState, DrawAction } from './types'

const generateId = (): string => crypto.randomUUID()

export const createLayer = (name: string): Layer => ({
  id: generateId(),
  name,
  visible: true,
  actions: [],
  thumbnailDataUrl: null,
})

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Layer 1')
  return {
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    width,
    height,
  }
}

export const addLayer = (state: CanvasState): CanvasState => {
  const layer = createLayer(`Layer ${state.layers.length + 1}`)
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state
  const filtered = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId =
    state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId
  return { ...state, layers: filtered, activeLayerId }
}

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
})

export const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
})

export const reorderLayers = (state: CanvasState, fromIndex: number, toIndex: number): CanvasState => {
  const layers = [...state.layers]
  const [moved] = layers.splice(fromIndex, 1)
  layers.splice(toIndex, 0, moved)
  return { ...state, layers }
}

export const addActionToLayer = (
  state: CanvasState,
  layerId: string,
  action: DrawAction,
): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, actions: [...l.actions, action] } : l,
  ),
})

export const clearLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, actions: [], thumbnailDataUrl: null } : l)),
})

export const clearAllLayers = (state: CanvasState): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => ({ ...l, actions: [], thumbnailDataUrl: null })),
})

export const getActiveLayer = (state: CanvasState): Layer | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId)

export const updateLayerThumbnail = (
  state: CanvasState,
  layerId: string,
  dataUrl: string,
): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, thumbnailDataUrl: dataUrl } : l)),
})

import type { HistoryEntry, CanvasState } from './types'

export type HistoryManager = {
  push: (entry: HistoryEntry) => void
  undo: (state: CanvasState) => CanvasState | null
  redo: (state: CanvasState) => CanvasState | null
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
}

export const createHistoryManager = (maxSize = 100): HistoryManager => {
  const undoStack: HistoryEntry[] = []
  const redoStack: HistoryEntry[] = []

  const push = (entry: HistoryEntry): void => {
    undoStack.push(entry)
    if (undoStack.length > maxSize) undoStack.shift()
    redoStack.length = 0
  }

  const undo = (state: CanvasState): CanvasState | null => {
    const entry = undoStack.pop()
    if (!entry) return null
    redoStack.push(entry)
    return {
      ...state,
      layers: state.layers.map((l) => {
        if (l.id !== entry.layerId) return l
        const actions = [...l.actions]
        actions.pop()
        return { ...l, actions }
      }),
    }
  }

  const redo = (state: CanvasState): CanvasState | null => {
    const entry = redoStack.pop()
    if (!entry) return null
    undoStack.push(entry)
    return {
      ...state,
      layers: state.layers.map((l) => {
        if (l.id !== entry.layerId) return l
        return { ...l, actions: [...l.actions, entry.action] }
      }),
    }
  }

  const canUndo = (): boolean => undoStack.length > 0
  const canRedo = (): boolean => redoStack.length > 0

  const clear = (): void => {
    undoStack.length = 0
    redoStack.length = 0
  }

  return { push, undo, redo, canUndo, canRedo, clear }
}

import type { CanvasState, DrawAction, Layer, Point } from './types'

export const renderAction = (ctx: CanvasRenderingContext2D, action: DrawAction): void => {
  ctx.save()
  if (action.kind === 'stroke') {
    ctx.lineCap = 'round'
    ctx.lineJoin = 'round'
    ctx.lineWidth = action.size
    if (action.tool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out'
      ctx.strokeStyle = 'rgba(0,0,0,1)'
    } else {
      ctx.globalCompositeOperation = 'source-over'
      ctx.strokeStyle = action.color
    }
    ctx.beginPath()
    const pts = action.points
    if (pts.length === 1) {
      ctx.arc(pts[0].x, pts[0].y, action.size / 2, 0, Math.PI * 2)
      ctx.fillStyle = action.tool === 'eraser' ? 'rgba(0,0,0,1)' : action.color
      ctx.fill()
    } else {
      ctx.moveTo(pts[0].x, pts[0].y)
      for (let i = 1; i < pts.length; i++) {
        const mid: Point = {
          x: (pts[i - 1].x + pts[i].x) / 2,
          y: (pts[i - 1].y + pts[i].y) / 2,
        }
        ctx.quadraticCurveTo(pts[i - 1].x, pts[i - 1].y, mid.x, mid.y)
      }
      ctx.lineTo(pts[pts.length - 1].x, pts[pts.length - 1].y)
      ctx.stroke()
    }
  } else if (action.kind === 'shape') {
    ctx.lineWidth = action.size
    ctx.strokeStyle = action.color
    ctx.lineCap = 'round'
    if (action.fillColor) {
      ctx.fillStyle = action.fillColor
    }
    const { start, end } = action
    switch (action.tool) {
      case 'rectangle': {
        const x = Math.min(start.x, end.x)
        const y = Math.min(start.y, end.y)
        const w = Math.abs(end.x - start.x)
        const h = Math.abs(end.y - start.y)
        if (action.fillColor) ctx.fillRect(x, y, w, h)
        ctx.strokeRect(x, y, w, h)
        break
      }
      case 'circle': {
        const cx = (start.x + end.x) / 2
        const cy = (start.y + end.y) / 2
        const rx = Math.abs(end.x - start.x) / 2
        const ry = Math.abs(end.y - start.y) / 2
        ctx.beginPath()
        ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
        if (action.fillColor) ctx.fill()
        ctx.stroke()
        break
      }
      case 'line': {
        ctx.beginPath()
        ctx.moveTo(start.x, start.y)
        ctx.lineTo(end.x, end.y)
        ctx.stroke()
        break
      }
    }
  }
  ctx.restore()
}

export const renderLayer = (ctx: CanvasRenderingContext2D, layer: Layer): void => {
  if (!layer.visible) return
  for (const action of layer.actions) {
    renderAction(ctx, action)
  }
}

export const renderCanvas = (
  ctx: CanvasRenderingContext2D,
  state: CanvasState,
): void => {
  ctx.clearRect(0, 0, state.width, state.height)
  // Draw checkerboard background for transparency
  drawCheckerboard(ctx, state.width, state.height)
  for (const layer of state.layers) {
    renderLayer(ctx, layer)
  }
}

const drawCheckerboard = (
  ctx: CanvasRenderingContext2D,
  width: number,
  height: number,
  size = 10,
): void => {
  ctx.save()
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, width, height)
  ctx.fillStyle = '#e0e0e0'
  for (let y = 0; y < height; y += size) {
    for (let x = 0; x < width; x += size) {
      if ((Math.floor(x / size) + Math.floor(y / size)) % 2 === 0) continue
      ctx.fillRect(x, y, size, size)
    }
  }
  ctx.restore()
}

export const renderLayerThumbnail = (
  layer: Layer,
  width: number,
  height: number,
  thumbWidth = 60,
  thumbHeight = 40,
): string => {
  const canvas = new OffscreenCanvas(thumbWidth, thumbHeight)
  const ctx = canvas.getContext('2d')
  if (!ctx) return ''
  ctx.scale(thumbWidth / width, thumbHeight / height)
  // White background
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, width, height)
  for (const action of layer.actions) {
    renderAction(ctx as unknown as CanvasRenderingContext2D, action)
  }
  return (canvas as unknown as HTMLCanvasElement).toDataURL?.('image/png') ?? ''
}

export const exportCanvasAsPng = (
  state: CanvasState,
): string => {
  const canvas = new OffscreenCanvas(state.width, state.height)
  const ctx = canvas.getContext('2d')
  if (!ctx) return ''
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, state.width, state.height)
  for (const layer of state.layers) {
    if (!layer.visible) continue
    for (const action of layer.actions) {
      renderAction(ctx as unknown as CanvasRenderingContext2D, action)
    }
  }
  return (canvas as unknown as HTMLCanvasElement).toDataURL?.('image/png') ?? ''
}

import type { DrawingFile, CanvasState } from './types'

const DATA_PATH = './data/drawings.json'

export const loadDrawings = async (): Promise<DrawingFile[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  try {
    return JSON.parse(text) as DrawingFile[]
  } catch {
    return []
  }
}

export const saveDrawing = async (
  name: string,
  state: CanvasState,
  existingId?: string,
): Promise<DrawingFile> => {
  const drawings = await loadDrawings()
  const now = new Date().toISOString()

  if (existingId) {
    const idx = drawings.findIndex((d) => d.id === existingId)
    if (idx >= 0) {
      drawings[idx] = {
        ...drawings[idx],
        name,
        updatedAt: now,
        state,
      }
      await Bun.write(DATA_PATH, JSON.stringify(drawings, null, 2))
      return drawings[idx]
    }
  }

  const drawing: DrawingFile = {
    id: crypto.randomUUID(),
    name,
    createdAt: now,
    updatedAt: now,
    state,
  }
  drawings.push(drawing)
  await Bun.write(DATA_PATH, JSON.stringify(drawings, null, 2))
  return drawing
}

export const loadDrawing = async (id: string): Promise<DrawingFile | null> => {
  const drawings = await loadDrawings()
  return drawings.find((d) => d.id === id) ?? null
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const drawings = await loadDrawings()
  const filtered = drawings.filter((d) => d.id !== id)
  if (filtered.length === drawings.length) return false
  await Bun.write(DATA_PATH, JSON.stringify(filtered, null, 2))
  return true
}

export const exportAsPngDataUrl = (canvasElement: HTMLCanvasElement): string =>
  canvasElement.toDataURL('image/png')

export const loadImageOntoCanvas = (
  ctx: CanvasRenderingContext2D,
  dataUrl: string,
): Promise<void> =>
  new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => {
      ctx.drawImage(img, 0, 0)
      resolve()
    }
    img.onerror = reject
    img.src = dataUrl
  })

