import type {
  CanvasState,
  ToolbarState,
  ToolType,
  Point,
  DrawAction,
  StrokeAction,
  ShapeAction,
} from './types'
import {
  createInitialState,
  addLayer,
  removeLayer,
  toggleLayerVisibility,
  setActiveLayer,
  addActionToLayer,
  clearLayer,
  clearAllLayers,
  getActiveLayer,
  updateLayerThumbnail,
} from './layers'
import { createHistoryManager } from './history'
import { renderCanvas as renderCanvasToCtx, renderLayerThumbnail, exportCanvasAsPng } from './renderer'
import { saveDrawing, loadDrawings, loadImageOntoCanvas } from './persistence'

export type CanvasController = {
  getState: () => CanvasState
  getToolbar: () => ToolbarState
  setTool: (tool: ToolType) => void
  setColor: (color: string) => void
  setFillColor: (color: string | null) => void
  setBrushSize: (size: number) => void
  startStroke: (point: Point) => void
  continueStroke: (point: Point) => void
  endStroke: () => void
  undo: () => void
  redo: () => void
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
  clearAll: () => void
  addLayer: () => void
  removeActiveLayer: () => void
  toggleLayer: (layerId: string) => void
  selectLayer: (layerId: string) => void
  savePng: () => string
  saveProject: (name: string) => Promise<void>
  loadPng: (ctx: CanvasRenderingContext2D, dataUrl: string) => Promise<void>
  render: (ctx: CanvasRenderingContext2D) => void
  updateThumbnails: () => void
}

export const createCanvasController = (width = 800, height = 600): CanvasController => {
  let state = createInitialState(width, height)
  let toolbar: ToolbarState = {
    activeTool: 'pen',
    color: '#000000',
    fillColor: null,
    brushSize: 3,
  }

  const history = createHistoryManager()
  let currentAction: DrawAction | null = null
  let isDrawing = false

  const setTool = (tool: ToolType): void => {
    toolbar = { ...toolbar, activeTool: tool }
  }

  const setColor = (color: string): void => {
    toolbar = { ...toolbar, color }
  }

  const setFillColor = (color: string | null): void => {
    toolbar = { ...toolbar, fillColor: color }
  }

  const setBrushSize = (size: number): void => {
    toolbar = { ...toolbar, brushSize: Math.max(1, Math.min(50, size)) }
  }

  const startStroke = (point: Point): void => {
    const activeLayer = getActiveLayer(state)
    if (!activeLayer || !activeLayer.visible) return
    isDrawing = true

    if (toolbar.activeTool === 'pen' || toolbar.activeTool === 'eraser') {
      currentAction = {
        kind: 'stroke',
        points: [point],
        color: toolbar.color,
        size: toolbar.brushSize,
        tool: toolbar.activeTool,
      } satisfies StrokeAction
    } else {
      currentAction = {
        kind: 'shape',
        tool: toolbar.activeTool as 'rectangle' | 'circle' | 'line',
        start: point,
        end: point,
        color: toolbar.color,
        fillColor: toolbar.fillColor,
        size: toolbar.brushSize,
      } satisfies ShapeAction
    }
  }

  const continueStroke = (point: Point): void => {
    if (!isDrawing || !currentAction) return

    if (currentAction.kind === 'stroke') {
      currentAction = {
        ...currentAction,
        points: [...currentAction.points, point],
      }
    } else {
      currentAction = {
        ...currentAction,
        end: point,
      }
    }
  }

  const endStroke = (): void => {
    if (!isDrawing || !currentAction) return
    isDrawing = false

    state = addActionToLayer(state, state.activeLayerId, currentAction)
    history.push({ layerId: state.activeLayerId, action: currentAction })
    currentAction = null
  }

  const undo = (): void => {
    const newState = history.undo(state)
    if (newState) state = newState
  }

  const redo = (): void => {
    const newState = history.redo(state)
    if (newState) state = newState
  }

  const clear = (): void => {
    state = clearLayer(state, state.activeLayerId)
    history.clear()
  }

  const clearAllFn = (): void => {
    state = clearAllLayers(state)
    history.clear()
  }

  const addLayerFn = (): void => {
    state = addLayer(state)
  }

  const removeActiveLayer = (): void => {
    state = removeLayer(state, state.activeLayerId)
  }

  const toggleLayer = (layerId: string): void => {
    state = toggleLayerVisibility(state, layerId)
  }

  const selectLayer = (layerId: string): void => {
    state = setActiveLayer(state, layerId)
  }

  const savePng = (): string => exportCanvasAsPng(state)

  const saveProject = async (name: string): Promise<void> => {
    await saveDrawing(name, state)
  }

  const loadPng = async (ctx: CanvasRenderingContext2D, dataUrl: string): Promise<void> => {
    await loadImageOntoCanvas(ctx, dataUrl)
  }

  const render = (ctx: CanvasRenderingContext2D): void => {
    renderCanvasToCtx(ctx, state)
    // Render current in-progress action
    if (isDrawing && currentAction) {
      ctx.save()
      const { renderAction } = require('./renderer')
      renderAction(ctx, currentAction)
      ctx.restore()
    }
  }

  const updateThumbnails = (): void => {
    for (const layer of state.layers) {
      const thumb = renderLayerThumbnail(layer, state.width, state.height)
      if (thumb) {
        state = updateLayerThumbnail(state, layer.id, thumb)
      }
    }
  }

  return {
    getState: () => state,
    getToolbar: () => toolbar,
    setTool,
    setColor,
    setFillColor,
    setBrushSize,
    startStroke,
    continueStroke,
    endStroke,
    undo,
    redo,
    canUndo: () => history.canUndo(),
    canRedo: () => history.canRedo(),
    clear,
    clearAll: clearAllFn,
    addLayer: addLayerFn,
    removeActiveLayer,
    toggleLayer,
    selectLayer,
    savePng,
    saveProject,
    loadPng,
    render,
    updateThumbnails,
  }
}

import { createSSR, h } from 'plaited'
import { createCanvasController } from './canvas'
import { renderApp } from './ui'
import { loadDrawings, saveDrawing } from './persistence'
import type { ToolType } from './types'

export { createCanvasController } from './canvas'
export { renderApp, renderToolbar, renderLayersPanel } from './ui'
export { renderCanvas, renderAction, exportCanvasAsPng } from './renderer'
export {
  createInitialState,
  addLayer,
  removeLayer,
  toggleLayerVisibility,
  clearLayer,
  clearAllLayers,
} from './layers'
export { createHistoryManager } from './history'
export { loadDrawings, saveDrawing, loadDrawing, deleteDrawing } from './persistence'
export type {
  ToolType,
  Point,
  DrawAction,
  StrokeAction,
  ShapeAction,
  Layer,
  CanvasState,
  ToolbarState,
  DrawingFile,
} from './types'

/**
 * Bootstraps the drawing canvas application in a browser context.
 * Attaches event listeners and manages the render loop.
 */
export const mountDrawingCanvas = (
  root: HTMLElement,
  width = 800,
  height = 600,
): void => {
  const controller = createCanvasController(width, height)

  const initialHtml = renderApp(
    controller.getState(),
    controller.getToolbar(),
    controller.canUndo(),
    controller.canRedo(),
  )

  root.innerHTML = typeof initialHtml === 'string' ? initialHtml : ''

  const canvasEl = root.querySelector<HTMLCanvasElement>('[p-target="drawing-canvas"]')
  if (!canvasEl) return

  const ctx = canvasEl.getContext('2d')
  if (!ctx) return

  let animFrame: number | null = null

  const scheduleRender = (): void => {
    if (animFrame) return
    animFrame = requestAnimationFrame(() => {
      controller.render(ctx)
      animFrame = null
    })
  }

  const reRenderUI = (): void => {
    controller.updateThumbnails()
    const html = renderApp(
      controller.getState(),
      controller.getToolbar(),
      controller.canUndo(),
      controller.canRedo(),
    )
    root.innerHTML = typeof html === 'string' ? html : ''
    reAttachCanvas()
  }

  const reAttachCanvas = (): void => {
    const newCanvas = root.querySelector<HTMLCanvasElement>('[p-target="drawing-canvas"]')
    if (!newCanvas) return
    const newCtx = newCanvas.getContext('2d')
    if (!newCtx) return
    attachCanvasListeners(newCanvas, newCtx)
    controller.render(newCtx)
  }

  const getCanvasPoint = (e: PointerEvent, canvas: HTMLCanvasElement) => {
    const rect = canvas.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  const attachCanvasListeners = (canvas: HTMLCanvasElement, drawCtx: CanvasRenderingContext2D): void => {
    canvas.addEventListener('pointerdown', (e) => {
      const point = getCanvasPoint(e, canvas)
      controller.startStroke(point)
      canvas.setPointerCapture(e.pointerId)
      scheduleRender()
    })

    canvas.addEventListener('pointermove', (e) => {
      const point = getCanvasPoint(e, canvas)
      controller.continueStroke(point)
      controller.render(drawCtx)
    })

    canvas.addEventListener('pointerup', () => {
      controller.endStroke()
      controller.render(drawCtx)
      controller.updateThumbnails()
      updateLayersPanelOnly()
    })
  }

  const updateLayersPanelOnly = (): void => {
    const layersList = root.querySelector('[p-target="layers-list"]')
    if (!layersList) return
    // Re-render just the layers panel would be ideal, but for simplicity
    // we update the full UI on stroke end
  }

  // Delegate click events for toolbar and layers panel
  root.addEventListener('click', (e) => {
    const target = e.target as HTMLElement
    const trigger = target.getAttribute('p-trigger')
    if (!trigger) return

    if (trigger.startsWith('tool-select:')) {
      const tool = trigger.split(':')[1] as ToolType
      controller.setTool(tool)
      reRenderUI()
      return
    }

    if (trigger === 'undo') {
      controller.undo()
      reRenderUI()
      return
    }

    if (trigger === 'redo') {
      controller.redo()
      reRenderUI()
      return
    }

    if (trigger === 'clear') {
      controller.clear()
      reRenderUI()
      return
    }

    if (trigger === 'save-png') {
      const dataUrl = controller.savePng()
      if (dataUrl) {
        const link = document.createElement('a')
        link.download = 'drawing.png'
        link.href = dataUrl
        link.click()
      }
      return
    }

    if (trigger === 'load-png') {
      const input = document.createElement('input')
      input.type = 'file'
      input.accept = 'image/png'
      input.onchange = () => {
        const file = input.files?.[0]
        if (!file) return
        const reader = new FileReader()
        reader.onload = async () => {
          const canvas = root.querySelector<HTMLCanvasElement>('[p-target="drawing-canvas"]')
          const drawCtx = canvas?.getContext('2d')
          if (drawCtx && typeof reader.result === 'string') {
            await controller.loadPng(drawCtx, reader.result)
          }
        }
        reader.readAsDataURL(file)
      }
      input.click()
      return
    }

    if (trigger === 'save-project') {
      const name = prompt('Drawing name:') ?? 'Untitled'
      controller.saveProject(name)
      return
    }

    if (trigger === 'toggle-fill') {
      const toolbar = controller.getToolbar()
      controller.setFillColor(toolbar.fillColor ? null : '#ffffff')
      reRenderUI()
      return
    }

    if (trigger === 'layer-add') {
      controller.addLayer()
      reRenderUI()
      return
    }

    if (trigger === 'layer-remove') {
      controller.removeActiveLayer()
      reRenderUI()
      return
    }

    if (trigger.startsWith('layer-select:')) {
      const layerId = trigger.split(':')[1]
      controller.selectLayer(layerId)
      reRenderUI()
      return
    }

    if (trigger.startsWith('layer-toggle:')) {
      const layerId = trigger.split(':')[1]
      controller.toggleLayer(layerId)
      reRenderUI()
      return
    }
  })

  // Handle input changes for color and brush size
  root.addEventListener('input', (e) => {
    const target = e.target as HTMLInputElement
    const trigger = target.getAttribute('p-trigger')
    if (!trigger) return

    if (trigger === 'color-change') {
      controller.setColor(target.value)
      return
    }

    if (trigger === 'fill-color-change') {
      controller.setFillColor(target.value)
      return
    }

    if (trigger === 'brush-size-change') {
      controller.setBrushSize(Number(target.value))
      const sizeLabel = target.nextElementSibling
      if (sizeLabel) sizeLabel.textContent = target.value
      return
    }
  })

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
      e.preventDefault()
      if (e.shiftKey) {
        controller.redo()
      } else {
        controller.undo()
      }
      reRenderUI()
    }
  })

  // Initial render
  attachCanvasListeners(canvasEl, ctx)
  controller.render(ctx)
}

/**
 * Server-side rendering entry point.
 * Returns the initial HTML for the drawing canvas.
 */
export const renderDrawingCanvasSSR = (width = 800, height = 600): string => {
  const controller = createCanvasController(width, height)
  const ssr = createSSR()
  const template = renderApp(
    controller.getState(),
    controller.getToolbar(),
    controller.canUndo(),
    controller.canRedo(),
  )
  return ssr(template)
}

