 96→    const { type } = state
 97→    if (type === 'pendulum') {
 98→      const params = state.pendulum.params as Record<string, number>
 99→      if (key in params) {
100→        params[key] = value
101→        state.pendulum.state = createPendulumState(state.pendulum.params)
102→      }
103→    } else if (type === 'projectile') {
104→      const params = state.projectile.params as Record<string, number>
105→      if (key in params) {
106→        params[key] = value
107→        state.projectile.state = createProjectileState(state.projectile.params)
108→      }
109→    } else if (type === 'spring') {
110→      const params = state.spring.params as Record<string, number>
111→      if (key in params) {
112→        params[key] = value
113→        state.spring.state = createSpringState(state.spring.params)
114→      }
115→    }
116→    // Reset to stopped when params change so user sees initial state
117→    state.playback = 'stopped'
118→  }
119→
120→  const tick = () => {
121→    if (state.playback !== 'playing') return
122→
123→    const dt = (DT * state.speed) / SUB_STEPS
124→
125→    for (let i = 0; i < SUB_STEPS; i++) {
126→      if (state.type === 'pendulum') {
127→        state.pendulum.state = stepPendulum(state.pendulum.state, state.pendulum.params, dt)
