281→  const dt = (DT * state.speed) / SUB_STEPS;
282→  for (let i = 0; i < SUB_STEPS; i++) {
283→    if (state.type === 'pendulum') {
284→      const p = state.pendulum;
285→      const next = rk4Pendulum(p.theta, p.omega, p.params.gravity, p.params.length, p.params.damping, dt);
286→      p.theta = next.theta;
287→      p.omega = next.omega;
288→      p.time += dt;
289→    } else if (state.type === 'projectile') {
290→      const pr = state.projectile;
291→      if (pr.landed) { state.playback = 'paused'; break; }
292→      pr.time += dt;
293→      const a = pr.params.angle*Math.PI/180;
294→      const v0 = pr.params.initialVelocity;
295→      const g = pr.params.gravity;
