/**
 * Client-side runtime for the Newton's Laws Simulator.
 * Handles the animation loop, event delegation, and DOM updates.
 * This script is inlined into the served HTML page.
 */

export const clientScript = `
<script type="module">
const DT = 1 / 60;
const SUB_STEPS = 4;

// ---- Physics Engine (inline for client) ----

const pendulumDeriv = (theta, omega, g, L, b) => ({
  dTheta: omega,
  dOmega: -(g / L) * Math.sin(theta) - b * omega,
});

const rk4Pendulum = (theta, omega, g, L, b, dt) => {
  const k1 = pendulumDeriv(theta, omega, g, L, b);
  const k2 = pendulumDeriv(theta + dt/2*k1.dTheta, omega + dt/2*k1.dOmega, g, L, b);
  const k3 = pendulumDeriv(theta + dt/2*k2.dTheta, omega + dt/2*k2.dOmega, g, L, b);
  const k4 = pendulumDeriv(theta + dt*k3.dTheta, omega + dt*k3.dOmega, g, L, b);
  return {
    theta: theta + (dt/6)*(k1.dTheta + 2*k2.dTheta + 2*k3.dTheta + k4.dTheta),
    omega: omega + (dt/6)*(k1.dOmega + 2*k2.dOmega + 2*k3.dOmega + k4.dOmega),
  };
};

const springDeriv = (x, v, k, m, b) => ({
  dx: v,
  dv: -(k/m)*x - b*v,
});

const rk4Spring = (x, v, k, m, b, dt) => {
  const k1 = springDeriv(x, v, k, m, b);
  const k2 = springDeriv(x + dt/2*k1.dx, v + dt/2*k1.dv, k, m, b);
  const k3 = springDeriv(x + dt/2*k2.dx, v + dt/2*k2.dv, k, m, b);
  const k4 = springDeriv(x + dt*k3.dx, v + dt*k3.dv, k, m, b);
  return {
    x: x + (dt/6)*(k1.dx + 2*k2.dx + 2*k3.dx + k4.dx),
    v: v + (dt/6)*(k1.dv + 2*k2.dv + 2*k3.dv + k4.dv),
  };
};

// ---- State ----

const state = {
  type: 'pendulum',
  playback: 'stopped',
  speed: 1,
  pendulum: {
    params: { length: 1.5, gravity: 9.81, initialAngle: 30, damping: 0 },
    theta: 30 * Math.PI / 180,
    omega: 0,
    time: 0,
  },
  projectile: {
    params: { angle: 45, initialVelocity: 20, gravity: 9.81 },
    time: 0,
    trail: [],
    landed: false,
  },
  spring: {
    params: { springConstant: 10, mass: 1.0, initialDisplacement: 0.5, damping: 0 },
    x: 0.5,
    v: 0,
    time: 0,
  },
};

const resetSim = () => {
  state.playback = 'stopped';
  const p = state.pendulum;
  p.theta = p.params.initialAngle * Math.PI / 180;
  p.omega = 0;
  p.time = 0;
  const pr = state.projectile;
  pr.time = 0;
  pr.trail = [{x:0,y:0}];
  pr.landed = false;
  const s = state.spring;
  s.x = s.params.initialDisplacement;
  s.v = 0;
  s.time = 0;
};

resetSim();

// ---- Rendering helpers ----

const fmt = (n, d=2) => Number.isFinite(n) ? n.toFixed(d) : '0.00';
const CANVAS_W = 600, CANVAS_H = 400;
const colors = {
  bg:'#0f172a', panel:'#1e293b', border:'#334155',
  accent:'#3b82f6', text:'#e2e8f0', textMuted:'#94a3b8',
  rod:'#64748b', bob:'#f59e0b', trail:'#10b981',
  proj:'#ef4444', spring:'#8b5cf6', mass:'#ec4899',
  ground:'#475569', grid:'#1e293b', ke:'#f59e0b', pe:'#3b82f6',
};

const svgNS = 'http://www.w3.org/2000/svg';
const el = (tag, attrs={}, ...ch) => {
  const isSvg = ['svg','line','circle','rect','text','path','polyline','defs','marker','g'].includes(tag);
  const e = isSvg ? document.createElementNS(svgNS, tag) : document.createElement(tag);
  for (const [k,v] of Object.entries(attrs)) e.setAttribute(k, String(v));
  ch.forEach(c => { if (typeof c === 'string') e.appendChild(document.createTextNode(c)); else if (c) e.appendChild(c); });
  return e;
};

// ---- Shared SVG arrow marker ----

const makeArrowDefs = (color) => {
  return el('defs', {},
    el('marker', {
      id: 'arrow', viewBox: '0 0 10 10', refX: '10', refY: '5',
      markerWidth: '6', markerHeight: '6', orient: 'auto-start-reverse',
    },
      el('path', { d: 'M 0 0 L 10 5 L 0 10 z', fill: color }),
    ),
  );
};

// ---- Canvas renderers ----

const renderPendulumSVG = () => {
  const p = state.pendulum;
  const L = p.params.length;
  const g = p.params.gravity;
  const cx = CANVAS_W/2, cy = 60;
  const scale = 120 / L;
  const posX = L * Math.sin(p.theta);
  const posY = L * Math.cos(p.theta);
  const bobX = cx + posX * scale;
  const bobY = cy + posY * scale;
  const angAcc = -(g/L)*Math.sin(p.theta) - p.params.damping*p.omega;
  const linVel = Math.abs(p.omega * L);
  const linAcc = Math.abs(angAcc * L);
  const height = L*(1-Math.cos(p.theta));
  const ke = 0.5*linVel*linVel;
  const pe = g*height;

  // Max energy for bar scaling
  const initAngleRad = p.params.initialAngle * Math.PI / 180;
  const maxE = g * L * (1 - Math.cos(initAngleRad));

  const svg = el('svg', {width:CANVAS_W, height:CANVAS_H, style:'background:'+colors.bg+';border-radius:8px;border:1px solid '+colors.border});

  // Arrow marker
  svg.appendChild(makeArrowDefs(colors.ke));

  // Grid lines
  for (let i=1;i<8;i++){const y=i*(CANVAS_H/8); svg.appendChild(el('line',{x1:0,y1:y,x2:CANVAS_W,y2:y,stroke:colors.grid,'stroke-width':1,'stroke-dasharray':'4,4'}));}

  // Pivot
  svg.appendChild(el('circle',{cx,cy,r:5,fill:colors.ground}));

  // Vertical reference
  svg.appendChild(el('line',{x1:cx,y1:cy,x2:cx,y2:cy+50,stroke:colors.textMuted,'stroke-width':1,'stroke-dasharray':'3,3'}));

  // Angle arc
  const arcR = 40;
  const arcStart = -p.params.initialAngle * Math.PI / 180;
  const arcEnd = p.params.initialAngle * Math.PI / 180;
  const ax1 = cx + arcR * Math.sin(arcStart);
  const ay1 = cy + arcR * Math.cos(arcStart);
  const ax2 = cx + arcR * Math.sin(arcEnd);
  const ay2 = cy + arcR * Math.cos(arcEnd);
  svg.appendChild(el('path',{
    d: 'M '+ax1+' '+ay1+' A '+arcR+' '+arcR+' 0 0 1 '+ax2+' '+ay2,
    fill:'none', stroke:colors.textMuted, 'stroke-width':1, 'stroke-dasharray':'3,3',
  }));

  // Rod
  svg.appendChild(el('line',{x1:cx,y1:cy,x2:bobX,y2:bobY,stroke:colors.rod,'stroke-width':2}));

  // Bob
  svg.appendChild(el('circle',{cx:bobX,cy:bobY,r:16,fill:colors.bob,stroke:'#d97706','stroke-width':2}));

  // Velocity vector arrow
  const vVecScale = scale * 0.5;
  const vAngle = p.theta + Math.PI/2;
  const vMag = p.omega * L;
  const vEndX = bobX + vMag * Math.cos(vAngle) * vVecScale * 0.3;
  const vEndY = bobY + vMag * Math.sin(vAngle) * vVecScale * 0.3;
  if (Math.abs(vMag) > 0.01) {
    svg.appendChild(el('line',{
      x1:bobX, y1:bobY, x2:vEndX, y2:vEndY,
      stroke:colors.ke, 'stroke-width':2, 'marker-end':'url(#arrow)',
    }));
  }

  // Energy bars
  const barBaseY = CANVAS_H - 30;
  const keH = maxE > 0 ? (ke / maxE) * 80 : 0;
  const peH = maxE > 0 ? (pe / maxE) * 80 : 0;
  svg.appendChild(el('rect',{x:CANVAS_W-60,y:barBaseY-keH,width:18,height:Math.max(keH,1),fill:colors.ke,rx:2}));
  svg.appendChild(el('text',{x:CANVAS_W-56,y:CANVAS_H-12,fill:colors.ke,'font-size':9,'font-family':'monospace'},'KE'));
  svg.appendChild(el('rect',{x:CANVAS_W-35,y:barBaseY-peH,width:18,height:Math.max(peH,1),fill:colors.pe,rx:2}));
  svg.appendChild(el('text',{x:CANVAS_W-31,y:CANVAS_H-12,fill:colors.pe,'font-size':9,'font-family':'monospace'},'PE'));

  // Labels
  svg.appendChild(el('text',{x:10,y:25,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'\\u03B8 = '+fmt(p.theta*180/Math.PI,1)+'\\u00B0'));
  svg.appendChild(el('text',{x:10,y:42,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'t = '+fmt(p.time,1)+'s'));

  return { svg, values: {
    angle: fmt(p.theta*180/Math.PI,1)+'\\u00B0', angVel: fmt(p.omega,3)+' rad/s',
    posX: fmt(posX,3)+' m', posY: fmt(posY,3)+' m',
    vel: fmt(linVel,3)+' m/s', acc: fmt(linAcc,3)+' m/s\\u00B2',
    ke: fmt(ke,3)+' J', pe: fmt(pe,3)+' J',
  }};
};

const renderProjectileSVG = () => {
  const pr = state.projectile;
  const a = pr.params.angle*Math.PI/180;
  const v0 = pr.params.initialVelocity;
  const g = pr.params.gravity;
  const t = pr.time;
  const maxRange = v0*v0*Math.sin(2*a)/g;
  const maxH = v0*v0*Math.sin(a)*Math.sin(a)/(2*g);
  const margin = 40;
  const plotW = CANVAS_W-2*margin, plotH = CANVAS_H-2*margin;
  const scale = Math.min(plotW/Math.max(maxRange*1.1,1), plotH/Math.max(maxH*1.3,1));
  const groundY = CANVAS_H-margin;
  const tx = x=>margin+x*scale, ty = y=>groundY-y*scale;

  const x = v0*Math.cos(a)*t;
  const y = v0*Math.sin(a)*t-0.5*g*t*t;
  const vx = v0*Math.cos(a);
  const vy = v0*Math.sin(a)-g*t;
  const spd = Math.sqrt(vx*vx+vy*vy);

  const svg = el('svg',{width:CANVAS_W,height:CANVAS_H,style:'background:'+colors.bg+';border-radius:8px;border:1px solid '+colors.border});

  // Arrow marker
  svg.appendChild(makeArrowDefs(colors.ke));

  // Ground
  svg.appendChild(el('line',{x1:margin,y1:groundY,x2:CANVAS_W-margin,y2:groundY,stroke:colors.ground,'stroke-width':2}));
  // Y axis
  svg.appendChild(el('line',{x1:margin,y1:margin,x2:margin,y2:groundY,stroke:colors.ground,'stroke-width':1}));
  // Grid
  for(let i=0;i<5;i++){const yy=groundY-(i+1)*plotH/6; svg.appendChild(el('line',{x1:margin,y1:yy,x2:CANVAS_W-margin,y2:yy,stroke:colors.grid,'stroke-width':1,'stroke-dasharray':'4,4'}));}

  // Launch angle indicator
  svg.appendChild(el('line',{
    x1:tx(0), y1:ty(0),
    x2:tx(maxRange*0.15*Math.cos(a)), y2:ty(maxRange*0.15*Math.sin(a)),
    stroke:colors.textMuted, 'stroke-width':1, 'stroke-dasharray':'4,4',
  }));

  // Trajectory trail
  if(pr.trail.length>1){
    const pts = pr.trail.map(p=>tx(p.x)+','+ty(p.y)).join(' ');
    svg.appendChild(el('polyline',{points:pts,fill:'none',stroke:colors.trail,'stroke-width':2,opacity:'0.7'}));
  }

  // Projectile
  const cy = Math.max(0,y);
  svg.appendChild(el('circle',{cx:tx(x),cy:ty(cy),r:8,fill:colors.proj,stroke:'#dc2626','stroke-width':2}));

  // Velocity vector
  if (!pr.landed && spd > 0.5) {
    const vScale = 1.5;
    svg.appendChild(el('line',{
      x1:tx(x), y1:ty(cy),
      x2:tx(x)+vx*vScale, y2:ty(cy)-vy*vScale,
      stroke:colors.ke, 'stroke-width':2, 'marker-end':'url(#arrow)',
    }));
  }

  // Labels
  svg.appendChild(el('text',{x:10,y:20,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'Range: '+fmt(maxRange,1)+'m'));
  svg.appendChild(el('text',{x:10,y:37,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'Max H: '+fmt(maxH,1)+'m'));
  svg.appendChild(el('text',{x:10,y:54,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'t = '+fmt(t,1)+'s'));

  return { svg, values: {
    posX: fmt(x,2)+' m', posY: fmt(Math.max(0,y),2)+' m',
    velX: fmt(vx,2)+' m/s', velY: fmt(pr.landed?0:vy,2)+' m/s',
    speed: fmt(pr.landed?0:spd,2)+' m/s', accY: fmt(-g,2)+' m/s\\u00B2',
    ke: fmt(0.5*spd*spd,2)+' J', pe: fmt(g*Math.max(0,y),2)+' J',
  }};
};

const renderSpringSVG = () => {
  const s = state.spring;
  const k = s.params.springConstant;
  const m = s.params.mass;
  const anchorX = 80, anchorY = CANVAS_H/2;
  const eqX = CANVAS_W/2, scale = 150;
  const massX = eqX + s.x * scale;
  const mSize = 30;
  const acc = -(k/m)*s.x - s.params.damping*s.v;
  const keV = 0.5*m*s.v*s.v;
  const peV = 0.5*k*s.x*s.x;
  const maxE = 0.5*k*s.params.initialDisplacement*s.params.initialDisplacement;

  const svg = el('svg',{width:CANVAS_W,height:CANVAS_H,style:'background:'+colors.bg+';border-radius:8px;border:1px solid '+colors.border});

  // Wall
  svg.appendChild(el('rect',{x:anchorX-5,y:anchorY-60,width:10,height:120,fill:colors.ground,rx:2}));
  for(let i=0;i<6;i++){const yy=anchorY-50+i*20; svg.appendChild(el('line',{x1:anchorX-5,y1:yy,x2:anchorX-15,y2:yy+10,stroke:colors.ground,'stroke-width':1}));}

  // Equilibrium line
  svg.appendChild(el('line',{x1:eqX,y1:anchorY-80,x2:eqX,y2:anchorY+80,stroke:colors.textMuted,'stroke-width':1,'stroke-dasharray':'4,4'}));
  svg.appendChild(el('text',{x:eqX-5,y:anchorY+95,fill:colors.textMuted,'font-size':10,'font-family':'monospace'},'x=0'));

  // Spring path
  const numCoils = 12;
  const sStartX = anchorX+20, sEndX = massX-mSize/2;
  const cw = (sEndX-sStartX)/numCoils, ca = 15;
  let d = 'M '+sStartX+' '+anchorY;
  for(let i=0;i<numCoils;i++){
    const x1=sStartX+(i+0.25)*cw, x2=sStartX+(i+0.75)*cw, x3=sStartX+(i+1)*cw;
    const yOff=i%2===0?-ca:ca;
    d+=' L '+x1+' '+(anchorY+yOff)+' L '+x2+' '+(anchorY-yOff)+' L '+x3+' '+anchorY;
  }
  svg.appendChild(el('path',{d,fill:'none',stroke:colors.spring,'stroke-width':2.5,'stroke-linecap':'round','stroke-linejoin':'round'}));

  // Mass block
  svg.appendChild(el('rect',{x:massX-mSize/2,y:anchorY-mSize/2,width:mSize,height:mSize,fill:colors.mass,stroke:'#db2777','stroke-width':2,rx:4}));
  svg.appendChild(el('text',{x:massX-5,y:anchorY+4,fill:'#fff','font-size':11,'font-family':'monospace','font-weight':'bold'},'m'));

  // Rail
  svg.appendChild(el('line',{x1:anchorX,y1:anchorY+mSize/2+5,x2:CANVAS_W-40,y2:anchorY+mSize/2+5,stroke:colors.ground,'stroke-width':1,'stroke-dasharray':'6,3'}));

  // Energy bars
  const keH = maxE>0?(keV/maxE)*80:0, peH = maxE>0?(peV/maxE)*80:0;
  svg.appendChild(el('rect',{x:CANVAS_W-60,y:CANVAS_H-30-keH,width:18,height:Math.max(keH,1),fill:colors.ke,rx:2}));
  svg.appendChild(el('text',{x:CANVAS_W-56,y:CANVAS_H-12,fill:colors.ke,'font-size':9,'font-family':'monospace'},'KE'));
  svg.appendChild(el('rect',{x:CANVAS_W-35,y:CANVAS_H-30-peH,width:18,height:Math.max(peH,1),fill:colors.pe,rx:2}));
  svg.appendChild(el('text',{x:CANVAS_W-31,y:CANVAS_H-12,fill:colors.pe,'font-size':9,'font-family':'monospace'},'PE'));

  // Labels
  svg.appendChild(el('text',{x:10,y:25,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'x = '+fmt(s.x,3)+'m'));
  svg.appendChild(el('text',{x:10,y:42,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'t = '+fmt(s.time,1)+'s'));

  return { svg, values: {
    disp: fmt(s.x,3)+' m', vel: fmt(s.v,3)+' m/s',
    acc: fmt(acc,3)+' m/s\\u00B2', time: fmt(s.time,2)+' s',
    ke: fmt(keV,4)+' J', pe: fmt(peV,4)+' J',
  }};
};

// ---- DOM update ----

const canvasContainer = document.getElementById('sim-canvas');
const valuesContainer = document.getElementById('sim-values');

const valueLabels = {
  pendulum: [['Angle','angle'],['Angular Vel','angVel'],['Position X','posX'],['Position Y','posY'],['Velocity','vel'],['Acceleration','acc'],['Kinetic E','ke'],['Potential E','pe']],
  projectile: [['Position X','posX'],['Position Y','posY'],['Velocity X','velX'],['Velocity Y','velY'],['Speed','speed'],['Accel Y','accY'],['Kinetic E','ke'],['Potential E','pe']],
  spring: [['Displacement','disp'],['Velocity','vel'],['Acceleration','acc'],['Time','time'],['Kinetic E','ke'],['Potential E','pe']],
};

const updateValues = (vals) => {
  const labels = valueLabels[state.type];
  let html = '';
  labels.forEach(([label, key]) => {
    const color = key === 'ke' ? colors.ke : key === 'pe' ? colors.pe : colors.text;
    html += '<div style="display:flex;justify-content:space-between;align-items:center">';
    html += '<span style="color:'+colors.textMuted+';font-size:11px">'+label+'</span>';
    html += '<span style="color:'+color+';font-size:12px;font-family:monospace;font-weight:600">'+vals[key]+'</span>';
    html += '</div>';
  });
  valuesContainer.innerHTML = html;
};

const render = () => {
  let result;
  if (state.type === 'pendulum') result = renderPendulumSVG();
  else if (state.type === 'projectile') result = renderProjectileSVG();
  else result = renderSpringSVG();
  canvasContainer.innerHTML = '';
  canvasContainer.appendChild(result.svg);
  updateValues(result.values);
};

// ---- Physics tick ----

const tick = () => {
  if (state.playback !== 'playing') return;
  const dt = (DT * state.speed) / SUB_STEPS;
  for (let i = 0; i < SUB_STEPS; i++) {
    if (state.type === 'pendulum') {
      const p = state.pendulum;
      const next = rk4Pendulum(p.theta, p.omega, p.params.gravity, p.params.length, p.params.damping, dt);
      p.theta = next.theta;
      p.omega = next.omega;
      p.time += dt;
    } else if (state.type === 'projectile') {
      const pr = state.projectile;
      if (pr.landed) { state.playback = 'paused'; break; }
      pr.time += dt;
      const a = pr.params.angle*Math.PI/180;
      const v0 = pr.params.initialVelocity;
      const g = pr.params.gravity;
      const x = v0*Math.cos(a)*pr.time;
      const y = v0*Math.sin(a)*pr.time - 0.5*g*pr.time*pr.time;
      if (y <= 0 && pr.time > 0.05) { pr.landed = true; state.playback = 'paused'; }
      pr.trail.push({x, y: Math.max(0,y)});
      if (pr.trail.length > 500) pr.trail = pr.trail.slice(-500);
    } else {
      const s = state.spring;
      const next = rk4Spring(s.x, s.v, s.params.springConstant, s.params.mass, s.params.damping, dt);
      s.x = next.x;
      s.v = next.v;
      s.time += dt;
    }
  }
};

// ---- Animation loop ----

let animId = null;
const loop = () => {
  tick();
  render();
  animId = requestAnimationFrame(loop);
};
loop();

// ---- Event handlers ----

const updateTabUI = () => {
  document.querySelectorAll('[data-tab]').forEach(btn => {
    const isActive = btn.dataset.tab === state.type;
    btn.style.background = isActive ? colors.accent : colors.panel;
    btn.style.color = isActive ? '#fff' : colors.textMuted;
  });
  const titles = { pendulum: 'Simple Pendulum', projectile: 'Projectile Motion', spring: 'Spring-Mass System' };
  const descs = {
    pendulum: 'F = -mg sin(\\u03B8) \\u2014 Oscillation under gravity',
    projectile: 'F = mg \\u2014 Parabolic trajectory under uniform gravity',
    spring: "F = -kx \\u2014 Simple harmonic motion (Hooke's Law)",
  };
  document.getElementById('sim-title').textContent = titles[state.type];
  document.getElementById('sim-desc').textContent = descs[state.type];
  updateSliders();
};

const updateSpeedUI = () => {
  document.querySelectorAll('[data-speed]').forEach(btn => {
    const isActive = parseFloat(btn.dataset.speed) === state.speed;
    btn.style.background = isActive ? colors.accent : colors.panel;
    btn.style.color = isActive ? '#fff' : colors.textMuted;
  });
};

const updatePlayBtn = () => {
  const btn = document.getElementById('play-btn');
  if (!btn) return;
  const isPlaying = state.playback === 'playing';
  btn.textContent = isPlaying ? 'Pause' : 'Play';
  btn.style.background = isPlaying ? colors.panel : colors.accent;
};

const sliderConfigs = {
  pendulum: [
    {id:'length',label:'Length',min:0.5,max:3,step:0.1,unit:'m',key:'length'},
    {id:'gravity',label:'Gravity',min:1,max:20,step:0.5,unit:'m/s\\u00B2',key:'gravity'},
    {id:'initialAngle',label:'Start Angle',min:5,max:80,step:1,unit:'\\u00B0',key:'initialAngle'},
    {id:'damping',label:'Damping',min:0,max:0.5,step:0.01,unit:'',key:'damping'},
  ],
  projectile: [
    {id:'angle',label:'Launch Angle',min:5,max:85,step:1,unit:'\\u00B0',key:'angle'},
    {id:'initialVelocity',label:'Init Velocity',min:5,max:50,step:1,unit:'m/s',key:'initialVelocity'},
    {id:'gravity',label:'Gravity',min:1,max:20,step:0.5,unit:'m/s\\u00B2',key:'gravity'},
  ],
  spring: [
    {id:'springConstant',label:'Spring k',min:1,max:50,step:1,unit:'N/m',key:'springConstant'},
    {id:'mass',label:'Mass',min:0.5,max:10,step:0.5,unit:'kg',key:'mass'},
    {id:'initialDisplacement',label:'Init Displ',min:0.1,max:1,step:0.05,unit:'m',key:'initialDisplacement'},
    {id:'damping',label:'Damping',min:0,max:0.5,step:0.01,unit:'',key:'damping'},
  ],
};

const getParams = () => {
  if (state.type === 'pendulum') return state.pendulum.params;
  if (state.type === 'projectile') return state.projectile.params;
  return state.spring.params;
};

const updateSliders = () => {
  const container = document.getElementById('sim-sliders');
  const configs = sliderConfigs[state.type];
  const params = getParams();
  let html = '';
  configs.forEach(c => {
    const val = params[c.key];
    html += '<div style="display:flex;align-items:center;gap:8px;margin:4px 0">';
    html += '<label for="'+c.id+'" style="color:'+colors.textMuted+';font-size:12px;min-width:100px">'+c.label+'</label>';
    html += '<input type="range" id="slider-'+c.id+'" min="'+c.min+'" max="'+c.max+'" step="'+c.step+'" value="'+val+'" data-param="'+c.key+'" style="flex:1;accent-color:'+colors.accent+'">';
    html += '<span id="val-'+c.id+'" style="color:'+colors.text+';font-size:12px;min-width:60px;text-align:right">'+fmt(val, c.step<1?2:1)+' '+c.unit+'</span>';
    html += '</div>';
  });
  container.innerHTML = html;

  // Rebind slider events
  configs.forEach(c => {
    const slider = document.getElementById('slider-'+c.id);
    if (!slider) return;
    slider.addEventListener('input', (e) => {
      const v = parseFloat(e.target.value);
      const params = getParams();
      params[c.key] = v;
      document.getElementById('val-'+c.id).textContent = fmt(v, c.step<1?2:1)+' '+c.unit;
      resetSim();
      updatePlayBtn();
      render();
    });
  });
};

// Tab clicks
document.querySelectorAll('[data-tab]').forEach(btn => {
  btn.addEventListener('click', () => {
    state.type = btn.dataset.tab;
    resetSim();
    updateTabUI();
    updatePlayBtn();
    render();
  });
});

// Play/Pause
document.getElementById('play-btn').addEventListener('click', () => {
  if (state.playback === 'playing') {
    state.playback = 'paused';
  } else {
    state.playback = 'playing';
  }
  updatePlayBtn();
});

// Reset
document.getElementById('reset-btn').addEventListener('click', () => {
  resetSim();
  updatePlayBtn();
  render();
});

// Speed
document.querySelectorAll('[data-speed]').forEach(btn => {
  btn.addEventListener('click', () => {
    state.speed = parseFloat(btn.dataset.speed);
    updateSpeedUI();
  });
});

// Initial setup
updateSliders();
render();
</script>
`;

