{
  "name": "@node/newton-sim",
  "version": "1.0.0",
  "description": "Interactive Newton's laws simulator with pendulum, projectile motion, and spring-mass systems",
  "main": "index.ts",
  "modnet": {
    "contentType": "science",
    "structure": "form",
    "mechanics": ["track", "chart"],
    "boundary": "all",
    "scale": 3
  },
  "dependencies": {
    "plaited": "latest"
  }
}

{
  "pendulum": {
    "default": { "length": 1.5, "gravity": 9.81, "initialAngle": 45, "damping": 0.001 },
    "moon": { "length": 1.5, "gravity": 1.62, "initialAngle": 45, "damping": 0.001 },
    "long": { "length": 3.0, "gravity": 9.81, "initialAngle": 30, "damping": 0.001 }
  },
  "projectile": {
    "default": { "angle": 45, "initialVelocity": 20, "gravity": 9.81 },
    "high": { "angle": 75, "initialVelocity": 30, "gravity": 9.81 },
    "fast": { "angle": 30, "initialVelocity": 50, "gravity": 9.81 }
  },
  "springMass": {
    "default": { "springConstant": 10, "mass": 1.0, "damping": 0.02, "initialDisplacement": 1.0 },
    "stiff": { "springConstant": 50, "mass": 1.0, "damping": 0.02, "initialDisplacement": 0.5 },
    "heavy": { "springConstant": 10, "mass": 8.0, "damping": 0.01, "initialDisplacement": 1.5 }
  }
}

export type Vec2 = { x: number; y: number };

export type SimStatus = 'playing' | 'paused' | 'reset';

export type SpeedMultiplier = 0.25 | 0.5 | 1 | 2;

export type PendulumParams = {
  length: number;
  gravity: number;
  initialAngle: number;
  damping: number;
};

export type PendulumState = {
  angle: number;
  angularVelocity: number;
  angularAcceleration: number;
  time: number;
  position: Vec2;
  velocity: Vec2;
  acceleration: Vec2;
};

export type ProjectileParams = {
  angle: number;
  initialVelocity: number;
  gravity: number;
};

export type ProjectileState = {
  time: number;
  position: Vec2;
  velocity: Vec2;
  acceleration: Vec2;
  trajectory: Vec2[];
  landed: boolean;
};

export type SpringParams = {
  springConstant: number;
  mass: number;
  damping: number;
  initialDisplacement: number;
};

export type SpringState = {
  displacement: number;
  velocity: number;
  acceleration: number;
  time: number;
};

export type SimConfig = {
  speed: SpeedMultiplier;
  dt: number;
};

export type ActiveSim = 'pendulum' | 'projectile' | 'spring-mass';

export type AppState = {
  activeSim: ActiveSim;
  status: SimStatus;
  config: SimConfig;
  pendulum: { params: PendulumParams; state: PendulumState };
  projectile: { params: ProjectileParams; state: ProjectileState };
  spring: { params: SpringParams; state: SpringState };
};

