  1→import { h } from 'plaited'
  2→import { createSSR } from 'plaited/ssr'
  3→import type {
  4→  SimulationType,
  5→  AppState,
  6→  PendulumParams,
  7→  PendulumState,
  8→  ProjectileParams,
  9→  ProjectileState,
 10→  SpringParams,
 11→  SpringState,
 12→} from './types'
 13→import { createPendulumState, updatePendulum } from './simulations/pendulum'
 14→import { createProjectileState, updateProjectile } from './simulations/projectile'
 15→import { createSpringState, updateSpring } from './simulations/spring-mass'
 16→import {
 17→  renderTabs,
 18→  renderPendulumView,
 19→  renderProjectileView,
 20→  renderSpringView,
 21→} from './ui/renderer'
 22→import { styles, styleStr } from './ui/styles'
 23→
 24→const DATA_PATH = './data/state.json'
 25→const FIXED_DT = 1 / 60
 26→
 27→// --- State management ---
 28→
 29→const loadPersistedState = async (): Promise<Record<string, unknown>> => {
 30→  try {
 31→    const file = Bun.file(DATA_PATH)
 32→    if (await file.exists()) {
 33→      return (await file.json()) as Record<string, unknown>
 34→    }
 35→  } catch {
 36→    // ignore
 37→  }
 38→  return {}
 39→}
 40→
 41→const saveState = async (state: AppState) => {
 42→  await Bun.write(
 43→    DATA_PATH,
 44→    JSON.stringify(
 45→      {
 46→        activeSimulation: state.activeSimulation,
 47→        pendulum: state.pendulumParams,
 48→        projectile: state.projectileParams,
 49→        spring: state.springParams,
 50→        speed: state.simulation.speed,
 51→        isPlaying: false,
 52→      },
 53→      null,
 54→      2,
 55→    ),
 56→  )
 57→}
 58→
 59→const createInitialState = async (): Promise<AppState> => {
 60→  const persisted = await loadPersistedState()
 61→
 62→  const pendulumParams: PendulumParams = {
 63→    length: (persisted.pendulum as PendulumParams)?.length ?? 1.5,
 64→    gravity: (persisted.pendulum as PendulumParams)?.gravity ?? 9.81,
 65→    initialAngle: (persisted.pendulum as PendulumParams)?.initialAngle ?? 0.5,
 66→    damping: 0.001,
 67→  }
 68→
 69→  const projectileParams: ProjectileParams = {
 70→    angle: (persisted.projectile as ProjectileParams)?.angle ?? 45,
 71→    initialVelocity: (persisted.projectile as ProjectileParams)?.initialVelocity ?? 20,
 72→    gravity: (persisted.projectile as ProjectileParams)?.gravity ?? 9.81,
 73→  }
 74→
 75→  const springParams: SpringParams = {
 76→    springConstant: (persisted.spring as SpringParams)?.springConstant ?? 10,
 77→    mass: (persisted.spring as SpringParams)?.mass ?? 1,
 78→    initialDisplacement: (persisted.spring as SpringParams)?.initialDisplacement ?? 1,
 79→    damping: 0.01,
 80→  }
 81→
 82→  return {
 83→    activeSimulation: (persisted.activeSimulation as SimulationType) ?? 'pendulum',
 84→    simulation: {
 85→      time: 0,
 86→      isPlaying: false,
 87→      speed: (persisted.speed as number) ?? 1,
 88→    },
 89→    pendulumParams,
 90→    pendulumState: createPendulumState(pendulumParams),
 91→    projectileParams,
 92→    projectileState: createProjectileState(projectileParams),
 93→    springParams,
 94→    springState: createSpringState(springParams),
 95→  }
 96→}
 97→
 98→// --- Simulation tick ---
 99→
100→const tick = (state: AppState): AppState => {
101→  if (!state.simulation.isPlaying) return state
102→
103→  const dt = FIXED_DT * state.simulation.speed
104→  const newTime = state.simulation.time + dt
105→
106→  return {
107→    ...state,
108→    simulation: { ...state.simulation, time: newTime },
109→    pendulumState:
110→      state.activeSimulation === 'pendulum'
111→        ? updatePendulum(state.pendulumState, state.pendulumParams, dt)
112→        : state.pendulumState,
113→    projectileState:
114→      state.activeSimulation === 'projectile'
115→        ? updateProjectile(state.projectileState, state.projectileParams, dt)
116→        : state.projectileState,
117→    springState:
118→      state.activeSimulation === 'spring'
119→        ? updateSpring(state.springState, state.springParams, dt)
120→        : state.springState,
121→  }
122→}
123→
124→// --- Event handling ---
125→
126→type SimEvent =
127→  | { type: 'tab'; sim: SimulationType }
128→  | { type: 'toggle-play' }
129→  | { type: 'reset' }
130→  | { type: 'set-speed'; speed: number }
131→  | { type: 'param'; key: string; value: number }
132→
133→const handleEvent = (state: AppState, event: SimEvent): AppState => {
134→  switch (event.type) {
135→    case 'tab':
136→      return {
137→        ...state,
138→        activeSimulation: event.sim,
139→      }
140→
141→    case 'toggle-play':
142→      return {
143→        ...state,
144→        simulation: {
145→          ...state.simulation,
146→          isPlaying: !state.simulation.isPlaying,
147→        },
148→      }
149→
150→    case 'reset': {
151→      const base = {
152→        ...state,
153→        simulation: { ...state.simulation, time: 0, isPlaying: false },
154→      }
155→      if (state.activeSimulation === 'pendulum') {
156→        return { ...base, pendulumState: createPendulumState(state.pendulumParams) }
157→      }
158→      if (state.activeSimulation === 'projectile') {
159→        return { ...base, projectileState: createProjectileState(state.projectileParams) }
160→      }
161→      return { ...base, springState: createSpringState(state.springParams) }
162→    }
163→
164→    case 'set-speed':
165→      return {
166→        ...state,
167→        simulation: { ...state.simulation, speed: event.speed },
168→      }
169→
170→    case 'param':
171→      return applyParam(state, event.key, event.value)
172→
173→    default:
174→      return state
175→  }
176→}
177→
178→const applyParam = (state: AppState, key: string, value: number): AppState => {
179→  switch (key) {
180→    case 'pendulum-length': {
181→      const params = { ...state.pendulumParams, length: value }
182→      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params) }
183→    }
184→    case 'pendulum-gravity': {
185→      const params = { ...state.pendulumParams, gravity: value }
186→      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params) }
187→    }
188→    case 'pendulum-angle': {
189→      const params = { ...state.pendulumParams, initialAngle: value }
190→      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params) }
191→    }
192→    case 'projectile-angle': {
193→      const params = { ...state.projectileParams, angle: value }
194→      return { ...state, projectileParams: params, projectileState: createProjectileState(params) }
195→    }
196→    case 'projectile-velocity': {
197→      const params = { ...state.projectileParams, initialVelocity: value }
198→      return { ...state, projectileParams: params, projectileState: createProjectileState(params) }
199→    }
200→    case 'projectile-gravity': {
201→      const params = { ...state.projectileParams, gravity: value }
202→      return { ...state, projectileParams: params, projectileState: createProjectileState(params) }
203→    }
204→    case 'spring-k': {
205→      const params = { ...state.springParams, springConstant: value }
206→      return { ...state, springParams: params, springState: createSpringState(params) }
207→    }
208→    case 'spring-mass': {
209→      const params = { ...state.springParams, mass: value }
210→      return { ...state, springParams: params, springState: createSpringState(params) }
211→    }
212→    case 'spring-disp': {
213→      const params = { ...state.springParams, initialDisplacement: value }
214→      return { ...state, springParams: params, springState: createSpringState(params) }
215→    }
216→    default:
217→      return state
218→  }
219→}
220→
221→// --- Render ---
222→
223→const render = (state: AppState) => {
224→  const { activeSimulation, simulation } = state
225→  const { isPlaying, speed, time } = simulation
226→
227→  const simView = (() => {
228→    switch (activeSimulation) {
229→      case 'pendulum':
230→        return renderPendulumView(state.pendulumState, state.pendulumParams, isPlaying, speed)
231→      case 'projectile':
232→        return renderProjectileView(state.projectileState, state.projectileParams, isPlaying, speed)
233→      case 'spring':
234→        return renderSpringView(state.springState, state.springParams, isPlaying, speed)
235→    }
236→  })()
237→
238→  return h(
239→    'div',
240→    { style: styleStr(styles.container) },
241→    h('h1', { style: styleStr(styles.header) }, "Newton's Laws Simulator"),
242→    renderTabs(activeSimulation),
243→    h(
244→      'div',
245→      {
246→        style: `font-size:12px;text-align:center;color:#adb5bd;margin-bottom:12px;font-feature-settings:"tnum"`,
247→      },
248→      `t = ${time.toFixed(2)}s`,
249→    ),
250→    simView,
251→  )
252→}
253→
254→// --- Server ---
255→
256→const renderToHtml = async (state: AppState): Promise<string> => {
257→  const ssr = createSSR()
258→  const vnode = render(state)
259→  const body = ssr(vnode)
260→
261→  return `<!DOCTYPE html>
262→<html lang="en">
263→<head>
264→  <meta charset="UTF-8">
265→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
266→  <title>Newton's Laws Simulator</title>
267→  <style>
268→    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
269→    body { background: #f0f2f5; padding: 20px; font-family: 'Inter', system-ui, sans-serif; }
270→    input[type="range"] { height: 6px; border-radius: 3px; }
271→    button:hover { opacity: 0.9; transform: translateY(-1px); }
272→    button:active { transform: translateY(0); }
273→  </style>
274→</head>
275→<body>
276→  ${body}
277→  <script>
278→    const TICK_INTERVAL = ${Math.round(1000 / 60)};
279→    let playing = false;
280→    let speed = ${state.simulation.speed};
281→
282→    // Client-side event delegation
283→    document.addEventListener('click', async (e) => {
284→      const btn = e.target.closest('[p-trigger]');
285→      if (!btn) return;
286→      const trigger = btn.getAttribute('p-trigger');
287→      let action = '';
288→
289→      if (trigger.startsWith('tab-')) {
290→        action = 'tab=' + trigger.replace('tab-', '');
291→      } else if (trigger === 'toggle-play') {
292→        action = 'toggle-play';
293→      } else if (trigger === 'reset') {
294→        action = 'reset';
295→      } else if (trigger === 'set-speed') {
296→        action = 'set-speed=' + btn.dataset.speed;
297→      }
298→
299→      if (action) {
300→        const res = await fetch('/event?action=' + encodeURIComponent(action));
301→        if (res.ok) document.body.innerHTML = await res.text();
302→      }
303→    });
304→
305→    document.addEventListener('input', async (e) => {
306→      const el = e.target;
307→      const trigger = el.getAttribute('p-trigger');
308→      if (!trigger || !trigger.startsWith('param-')) return;
309→      const key = trigger.replace('param-', '');
310→      const res = await fetch('/event?action=param&key=' + key + '&value=' + el.value);
311→      if (res.ok) document.body.innerHTML = await res.text();
312→    });
313→
314→    // Animation loop via server ticks
315→    const tickLoop = async () => {
316→      const res = await fetch('/tick');
317→      if (res.ok) {
318→        const html = await res.text();
319→        if (html.trim()) document.body.innerHTML = html;
320→      }
321→    };
322→    setInterval(tickLoop, TICK_INTERVAL);
323→  </script>
324→</body>
325→</html>`
