328→const main = async () => {
329→  let state = await createInitialState()
330→
331→  const server = Bun.serve({
332→    port: 3000,
333→    fetch: async (req) => {
334→      const url = new URL(req.url)
335→
336→      if (url.pathname === '/tick') {
337→        state = tick(state)
338→        if (!state.simulation.isPlaying) {
339→          return new Response('', { headers: { 'Content-Type': 'text/html' } })
340→        }
341→        const ssr = createSSR()
342→        const body = ssr(render(state))
343→        return new Response(body, { headers: { 'Content-Type': 'text/html' } })
344→      }
345→
346→      if (url.pathname === '/event') {
347→        const action = url.searchParams.get('action') ?? ''
348→
349→        if (action.startsWith('tab=')) {
350→          const sim = action.replace('tab=', '') as SimulationType
351→          state = handleEvent(state, { type: 'tab', sim })
352→        } else if (action === 'toggle-play') {
353→          state = handleEvent(state, { type: 'toggle-play' })
354→        } else if (action === 'reset') {
