361→          const value = parseFloat(url.searchParams.get('value') ?? '0')
362→          state = handleEvent(state, { type: 'param', key, value })
363→        }
364→
365→        await saveState(state)
366→        const ssr = createSSR()
367→        const body = ssr(render(state))
