371→      // Default: full page
372→      const html = await renderToHtml(state)
373→      return new Response(html, { headers: { 'Content-Type': 'text/html' } })
374→    },
375→  })
376→
377→  console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)
378→}
